import { useState, useEffect, useRef, useCallback } from 'react';
import { api } from '../utils/api';

const mono = "'JetBrains Mono', 'SF Mono', monospace";
const body = "'Plus Jakarta Sans', -apple-system, sans-serif";

const PHASES = {
  WAITING: 'waiting',
  FIRST_TRADE: 'first_trade',
  CONFIRMED: 'confirmed',
  HIDDEN: 'hidden',
};

export default function FirstTradeAccelerator() {
  const [phase, setPhase] = useState(PHASES.WAITING);
  const [firstTrade, setFirstTrade] = useState(null);
  const [dots, setDots] = useState('');
  const [elapsed, setElapsed] = useState(0);
  const startTime = useRef(Date.now());
  const pollRef = useRef(null);
  const dotRef = useRef(null);

  // Check if user already has trades — if so, hide component
  const checkExistingTrades = useCallback(async () => {
    // If localStorage says user has seen first trade, skip
    if (localStorage.getItem('aura_first_trade_seen')) {
      setPhase(PHASES.HIDDEN);
      return true;
    }

    try {
      // Try paper trades first, then real positions
      let positions = [];
      try {
        const paperData = await api('/paper/positions', { silent: true });
        positions = Array.isArray(paperData) ? paperData : paperData?.positions || [];
      } catch {
        // Fall back to real positions
        try {
          const posData = await api('/positions', { silent: true });
          positions = Array.isArray(posData) ? posData : posData?.positions || [];
        } catch {
          positions = [];
        }
      }

      if (positions.length > 0) {
        localStorage.setItem('aura_first_trade_seen', 'true');
        setPhase(PHASES.HIDDEN);
        return true;
      }
      return false;
    } catch {
      return false;
    }
  }, []);

  // Initial check
  useEffect(() => {
    checkExistingTrades();
  }, [checkExistingTrades]);

  // Animated dots for the waiting state
  useEffect(() => {
    if (phase !== PHASES.WAITING) return;
    dotRef.current = setInterval(() => {
      setDots((prev) => prev.length >= 3 ? '' : prev + '.');
    }, 500);
    return () => clearInterval(dotRef.current);
  }, [phase]);

  // Elapsed timer
  useEffect(() => {
    if (phase !== PHASES.WAITING) return;
    const iv = setInterval(() => {
      const secs = Math.floor((Date.now() - startTime.current) / 1000);
      setElapsed(secs);
    }, 1000);
    return () => clearInterval(iv);
  }, [phase]);

  // Poll for first position every 10 seconds
  useEffect(() => {
    if (phase !== PHASES.WAITING) return;

    const poll = async () => {
      // Hide after 5 minutes of waiting
      if (Date.now() - startTime.current > 5 * 60 * 1000) {
        setPhase(PHASES.HIDDEN);
        return;
      }

      try {
        let positions = [];
        try {
          const paperData = await api('/paper/positions', { silent: true });
          positions = Array.isArray(paperData) ? paperData : paperData?.positions || [];
        } catch {
          try {
            const posData = await api('/positions', { silent: true });
            positions = Array.isArray(posData) ? posData : posData?.positions || [];
          } catch {
            positions = [];
          }
        }

        if (positions.length > 0) {
          const trade = positions[0];
          setFirstTrade({
            symbol: trade.symbol || trade.contract?.symbol || '???',
            side: (trade.side || trade.action || 'BUY').toUpperCase(),
            price: Number(trade.avg_cost || trade.avgCost || trade.entryPrice || trade.marketPrice || 0),
            qty: trade.qty || trade.quantity || trade.position || 0,
          });
          setPhase(PHASES.FIRST_TRADE);
          localStorage.setItem('aura_first_trade_seen', 'true');

          // Transition to confirmed after 8 seconds
          setTimeout(() => setPhase(PHASES.CONFIRMED), 8000);
          // Hide after 15 seconds total
          setTimeout(() => setPhase(PHASES.HIDDEN), 15000);
        }
      } catch {
        // Keep polling
      }
    };

    poll();
    pollRef.current = setInterval(poll, 10000);
    return () => clearInterval(pollRef.current);
  }, [phase]);

  if (phase === PHASES.HIDDEN) return null;

  const formatElapsed = () => {
    const mins = Math.floor(elapsed / 60);
    const secs = elapsed % 60;
    return mins > 0 ? `${mins}m ${secs}s` : `${secs}s`;
  };

  return (
    <>
      <style>{`
        @keyframes fta-borderPulse {
          0%, 100% { border-color: rgba(34,197,94,0.3); box-shadow: 0 0 20px rgba(34,197,94,0.05); }
          50% { border-color: rgba(34,197,94,0.6); box-shadow: 0 0 30px rgba(34,197,94,0.1); }
        }
        @keyframes fta-celebrateBorder {
          0% { border-color: #22C55E; box-shadow: 0 0 20px rgba(34,197,94,0.2); }
          25% { border-color: #60A5FA; box-shadow: 0 0 30px rgba(96,165,250,0.2); }
          50% { border-color: #22C55E; box-shadow: 0 0 40px rgba(34,197,94,0.3); }
          75% { border-color: #A78BFA; box-shadow: 0 0 30px rgba(167,139,250,0.2); }
          100% { border-color: #22C55E; box-shadow: 0 0 20px rgba(34,197,94,0.2); }
        }
        @keyframes fta-slideIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes fta-sparkle {
          0%, 100% { opacity: 0; transform: scale(0) rotate(0deg); }
          50% { opacity: 1; transform: scale(1) rotate(180deg); }
        }
        @keyframes fta-scanLine {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
      `}</style>
      <div
        style={{
          background: 'rgba(15,22,32,0.65)',
          backdropFilter: 'blur(16px)',
          WebkitBackdropFilter: 'blur(16px)',
          border: '1px solid rgba(34,197,94,0.3)',
          borderRadius: 12,
          padding: '16px 20px',
          marginBottom: 16,
          animation: phase === PHASES.FIRST_TRADE
            ? 'fta-celebrateBorder 2s ease infinite, fta-slideIn 0.4s ease'
            : 'fta-borderPulse 3s ease-in-out infinite, fta-slideIn 0.4s ease',
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        {/* Scan line effect for waiting state */}
        {phase === PHASES.WAITING && (
          <div style={{
            position: 'absolute', top: 0, left: 0, width: '50%', height: '100%',
            background: 'linear-gradient(90deg, transparent, rgba(34,197,94,0.04), transparent)',
            animation: 'fta-scanLine 3s ease-in-out infinite',
            pointerEvents: 'none',
          }} />
        )}

        {/* Sparkle particles for first trade celebration */}
        {phase === PHASES.FIRST_TRADE && (
          <>
            {[...Array(6)].map((_, i) => (
              <div key={i} style={{
                position: 'absolute',
                top: `${15 + Math.random() * 70}%`,
                left: `${5 + Math.random() * 90}%`,
                width: 4, height: 4,
                borderRadius: '50%',
                background: i % 2 === 0 ? '#22C55E' : '#60A5FA',
                animation: `fta-sparkle ${1.5 + Math.random()}s ease-in-out ${Math.random() * 0.5}s infinite`,
                pointerEvents: 'none',
              }} />
            ))}
          </>
        )}

        {phase === PHASES.WAITING && (
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            {/* Animated scanning indicator */}
            <div style={{
              width: 40, height: 40, borderRadius: 10,
              background: 'rgba(245,158,11,0.1)',
              border: '1px solid rgba(245,158,11,0.3)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              flexShrink: 0,
            }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#F59E0B" strokeWidth="2">
                <polyline points="22 7 13.5 15.5 8.5 10.5 2 17" />
                <polyline points="16 7 22 7 22 13" />
              </svg>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{
                fontFamily: body, fontSize: 14, fontWeight: 600,
                color: '#E5E7DB', marginBottom: 4,
              }}>
                Your system is generating signals{dots}
              </div>
              <div style={{
                fontFamily: body, fontSize: 12, color: '#90A3AF',
              }}>
                First paper trade expected within minutes. The signal engine is scanning for high-confidence setups.
              </div>
            </div>
            <div style={{
              fontFamily: mono, fontSize: 11, color: '#4B5563',
              textAlign: 'right', flexShrink: 0,
            }}>
              {formatElapsed()}
            </div>
          </div>
        )}

        {phase === PHASES.FIRST_TRADE && firstTrade && (
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <div style={{
              width: 40, height: 40, borderRadius: 10,
              background: 'rgba(34,197,94,0.15)',
              border: '1px solid rgba(34,197,94,0.4)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              flexShrink: 0,
            }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#22C55E" strokeWidth="2.5">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{
                fontFamily: body, fontSize: 14, fontWeight: 600,
                color: '#22C55E', marginBottom: 4,
              }}>
                First trade placed
              </div>
              <div style={{
                fontFamily: mono, fontSize: 15, fontWeight: 700,
                color: '#E5E7DB', marginBottom: 2,
              }}>
                {firstTrade.side} {firstTrade.symbol}
                {firstTrade.price > 0 ? ` at $${firstTrade.price.toFixed(2)}` : ''}
              </div>
              <div style={{
                fontFamily: body, fontSize: 12, color: '#90A3AF',
              }}>
                The system is working. More trades will follow automatically.
              </div>
            </div>
          </div>
        )}

        {phase === PHASES.CONFIRMED && (
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <div style={{
              width: 40, height: 40, borderRadius: 10,
              background: 'rgba(34,197,94,0.1)',
              border: '1px solid rgba(34,197,94,0.2)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              flexShrink: 0,
            }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#22C55E" strokeWidth="2">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            </div>
            <div style={{ flex: 1 }}>
              <div style={{
                fontFamily: body, fontSize: 14, fontWeight: 600,
                color: '#E5E7DB', marginBottom: 4,
              }}>
                System confirmed active
              </div>
              <div style={{
                fontFamily: body, fontSize: 12, color: '#90A3AF',
              }}>
                Your bots are monitoring markets and executing trades. Check back anytime for updates.
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
