import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { tokens } from '../styles/tokens';
import GlassPanel from './ui/GlassPanel';

// ─── Onboarding Steps ────────────────────────────────────────────────────────

const STEPS = [
  { id: 'explore_strategies', label: 'Explore Strategy Catalogue', description: 'Browse 83 backtested strategies across equity, crypto, and 14 regions', path: '/leaderboard', icon: '\u{1F4CA}' },
  { id: 'view_backtest', label: 'View a Backtest', description: "Deep-dive into a strategy's historical performance and risk metrics", path: '/strategies/breakout', icon: '\u{1F4C8}' },
  { id: 'check_risk', label: 'Review Risk Dashboard', description: 'Understand your portfolio risk exposure, drawdown limits, and correlation', path: '/risk', icon: '\u{1F6E1}\uFE0F' },
  { id: 'connect_broker', label: 'Connect Your Broker', description: 'Link IBKR, Alpaca, or Kraken for live execution', path: '/gateway', icon: '\u{1F517}' },
  { id: 'paper_trade', label: 'Start Paper Trading', description: 'Test strategies risk-free with simulated capital', path: '/paper-trading', icon: '\u{1F4DD}' },
  { id: 'first_strategy', label: 'Promote a Strategy to Live', description: 'Move your first strategy from backtest to live execution', path: '/strategies', icon: '\u{1F680}' },
];

const STORAGE_KEY = 'aura_onboarding_progress';
const DISMISS_KEY = 'aura_onboarding_dismissed';

// ─── Component ───────────────────────────────────────────────────────────────

export default function OnboardingChecklist() {
  const navigate = useNavigate();
  const [completed, setCompleted] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
    } catch {
      return [];
    }
  });
  const [dismissed, setDismissed] = useState(() =>
    localStorage.getItem(DISMISS_KEY) === 'true'
  );

  // Auto-mark current path's step as complete on mount
  useEffect(() => {
    const path = window.location.pathname;
    const match = STEPS.find(
      (s) => path === s.path || path.startsWith(s.path + '/')
    );
    if (match && !completed.includes(match.id)) {
      const next = [...completed, match.id];
      setCompleted(next);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Persist progress on change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(completed));
  }, [completed]);

  if (dismissed) return null;

  const allDone = completed.length >= STEPS.length;
  const completedCount = completed.length;
  const progressPct = (completedCount / STEPS.length) * 100;

  function markComplete(id) {
    if (!completed.includes(id)) {
      setCompleted((prev) => [...prev, id]);
    }
  }

  function handleGo(step) {
    markComplete(step.id);
    navigate(step.path);
  }

  function handleDismiss() {
    localStorage.setItem(DISMISS_KEY, 'true');
    setDismissed(true);
  }

  // ─── Animation variants ──────────────────────────────────────────────────

  const containerVariants = {
    hidden: {},
    show: { transition: { staggerChildren: 0.06 } },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 8 },
    show: { opacity: 1, y: 0, transition: { duration: 0.2, ease: [0.4, 0, 0.2, 1] } },
  };

  // ─── Render ──────────────────────────────────────────────────────────────

  return (
    <GlassPanel style={{ marginBottom: 16 }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        marginBottom: 12,
      }}>
        <h3 style={{
          fontFamily: tokens.font.sans,
          fontSize: tokens.fontSize.lg,
          fontWeight: tokens.fontWeight.semibold,
          color: tokens.color.text,
          margin: 0,
        }}>
          Getting Started
        </h3>
        <span style={{
          fontFamily: tokens.font.mono,
          fontSize: tokens.fontSize.sm,
          color: tokens.color.textSecondary,
        }}>
          {completedCount}/{STEPS.length} complete
        </span>
      </div>

      {/* Progress bar */}
      <div style={{
        width: '100%',
        height: 6,
        borderRadius: tokens.radius.full,
        background: tokens.color.surfaceHover,
        marginBottom: 16,
        overflow: 'hidden',
      }}>
        <div style={{
          height: '100%',
          borderRadius: tokens.radius.full,
          background: tokens.color.green,
          width: `${progressPct}%`,
          transition: 'width 0.4s ease',
        }} />
      </div>

      {/* All done celebration */}
      {allDone ? (
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.3 }}
          style={{ textAlign: 'center', padding: '20px 0 8px' }}
        >
          <div style={{
            fontFamily: tokens.font.sans,
            fontSize: tokens.fontSize.xl,
            fontWeight: tokens.fontWeight.bold,
            color: tokens.color.green,
            marginBottom: 8,
          }}>
            Setup Complete!
          </div>
          <div style={{
            fontFamily: tokens.font.sans,
            fontSize: tokens.fontSize.base,
            color: tokens.color.textSecondary,
            marginBottom: 16,
          }}>
            You're fully onboarded. Your trading desk is ready.
          </div>
          <button
            style={{
              fontFamily: tokens.font.sans,
              fontSize: tokens.fontSize.base,
              fontWeight: tokens.fontWeight.medium,
              color: '#fff',
              background: tokens.color.green,
              border: 'none',
              borderRadius: tokens.radius.md,
              padding: '8px 24px',
              cursor: 'pointer',
              transition: tokens.transition.fast,
            }}
            onClick={handleDismiss}
          >
            Dismiss
          </button>
        </motion.div>
      ) : (
        <>
          {/* Steps list */}
          <motion.div
            variants={containerVariants}
            initial="hidden"
            animate="show"
          >
            {STEPS.map((step) => {
              const done = completed.includes(step.id);
              return (
                <motion.div
                  key={step.id}
                  variants={itemVariants}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 12,
                    padding: '10px 12px',
                    borderRadius: tokens.radius.md,
                    background: done ? `color-mix(in srgb, ${tokens.color.green} 4%, transparent)` : 'transparent',
                    transition: tokens.transition.fast,
                    cursor: done ? 'default' : 'pointer',
                  }}
                  onMouseEnter={
                    !done
                      ? (e) => { e.currentTarget.style.background = tokens.color.surfaceHover; }
                      : undefined
                  }
                  onMouseLeave={
                    !done
                      ? (e) => { e.currentTarget.style.background = 'transparent'; }
                      : undefined
                  }
                  onClick={() => !done && handleGo(step)}
                >
                  {/* Checkbox */}
                  <div style={{
                    width: 22,
                    height: 22,
                    borderRadius: tokens.radius.sm,
                    border: done ? 'none' : `2px solid ${tokens.color.textMuted}`,
                    background: done ? tokens.color.green : 'transparent',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    flexShrink: 0,
                    transition: tokens.transition.fast,
                  }}>
                    {done && (
                      <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                        <path
                          d="M3 7.5L5.5 10L11 4"
                          stroke="#fff"
                          strokeWidth="2"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                        />
                      </svg>
                    )}
                  </div>

                  {/* Icon */}
                  <span style={{ fontSize: 18, flexShrink: 0, width: 24, textAlign: 'center' }}>
                    {step.icon}
                  </span>

                  {/* Text */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{
                      fontFamily: tokens.font.sans,
                      fontSize: tokens.fontSize.base,
                      fontWeight: tokens.fontWeight.medium,
                      color: done ? tokens.color.textSecondary : tokens.color.text,
                      textDecoration: done ? 'line-through' : 'none',
                      opacity: done ? 0.6 : 1,
                    }}>
                      {step.label}
                    </div>
                    <div style={{
                      fontFamily: tokens.font.sans,
                      fontSize: tokens.fontSize.xs,
                      color: tokens.color.textMuted,
                      opacity: done ? 0.5 : 0.8,
                      marginTop: 4,
                    }}>
                      {step.description}
                    </div>
                  </div>

                  {/* Go button */}
                  {!done && (
                    <button
                      style={{
                        fontFamily: tokens.font.sans,
                        fontSize: tokens.fontSize.sm,
                        fontWeight: tokens.fontWeight.medium,
                        color: tokens.color.blue,
                        background: 'none',
                        border: 'none',
                        cursor: 'pointer',
                        padding: '4px 10px',
                        borderRadius: tokens.radius.sm,
                        transition: tokens.transition.fast,
                        whiteSpace: 'nowrap',
                        flexShrink: 0,
                      }}
                      onClick={(e) => {
                        e.stopPropagation();
                        handleGo(step);
                      }}
                      onMouseEnter={(e) => { e.currentTarget.style.background = `color-mix(in srgb, ${tokens.color.blue} 10%, transparent)`; }}
                      onMouseLeave={(e) => { e.currentTarget.style.background = 'none'; }}
                    >
                      Go &rarr;
                    </button>
                  )}
                </motion.div>
              );
            })}
          </motion.div>

          {/* Skip link */}
          <div style={{ textAlign: 'center', marginTop: 8 }}>
            <button
              style={{
                fontFamily: tokens.font.sans,
                fontSize: tokens.fontSize.xs,
                color: tokens.color.textSecondary,
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                padding: '8px 0',
                textDecoration: 'underline',
                textUnderlineOffset: 2,
                transition: tokens.transition.fast,
              }}
              onClick={handleDismiss}
              onMouseEnter={(e) => { e.currentTarget.style.color = tokens.color.textSecondary; }}
              onMouseLeave={(e) => { e.currentTarget.style.color = tokens.color.textMuted; }}
            >
              Skip onboarding
            </button>
          </div>
        </>
      )}
    </GlassPanel>
  );
}
