/**
 * BotHealthGauge — WHOOP-style SVG circular arc gauge for bot P&L
 *
 * Props:
 *   value    — 0-100 fill percentage (maps P&L % to gauge fill)
 *   label    — Bot name (ALPHA, BETA, CRYPTO)
 *   color    — Arc fill color
 *   size     — Gauge diameter (default 140)
 *   pnlText  — Formatted P&L string displayed in center
 *   subText  — Secondary text (e.g., "Daily P&L")
 */
import { useEffect } from 'react';
import { motion, useSpring, useTransform } from 'framer-motion';
import { RAW as HEX, fonts } from '../tokens';

const ARC_DEGREES = 270;
const START_ANGLE = 135;
const STROKE_WIDTH = 10;
const DIM_ARC = 'rgba(255,255,255,0.05)';

function polarToCartesian(cx, cy, r, angleDeg) {
  const rad = (angleDeg * Math.PI) / 180;
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) };
}

function describeArc(cx, cy, r, startAngle, endAngle) {
  const start = polarToCartesian(cx, cy, r, endAngle);
  const end = polarToCartesian(cx, cy, r, startAngle);
  const largeArc = endAngle - startAngle > 180 ? 1 : 0;
  return `M ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y}`;
}

function arcLength(degrees, radius) {
  return (degrees / 360) * 2 * Math.PI * radius;
}

export default function BotHealthGauge({ value = 0, label, color, size = 140, pnlText, subText }) {
  const radius = (size - STROKE_WIDTH) / 2;
  const center = size / 2;
  const bgArc = describeArc(center, center, radius, START_ANGLE, START_ANGLE + ARC_DEGREES);
  const fullArcLen = arcLength(ARC_DEGREES, radius);

  const pct = Math.min(1, Math.max(0, value / 100));
  const springPct = useSpring(0, { stiffness: 40, damping: 18 });
  const dashOffset = useTransform(springPct, [0, 1], [fullArcLen, 0]);

  useEffect(() => {
    springPct.set(pct);
  }, [pct, springPct]);

  const filterId = `glow-${(label || 'bot').replace(/\s/g, '')}`;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flex: '0 0 auto' }}>
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{ overflow: 'visible' }}>
        <defs>
          <filter id={filterId} x="-50%" y="-50%" width="200%" height="200%">
            <feDropShadow dx="0" dy="0" stdDeviation="6" floodColor={color} floodOpacity="0.5" />
          </filter>
        </defs>

        {/* Background arc */}
        <path d={bgArc} fill="none" stroke={DIM_ARC} strokeWidth={STROKE_WIDTH} strokeLinecap="round" />

        {/* Animated fill arc */}
        <motion.path
          d={bgArc}
          fill="none"
          stroke={color}
          strokeWidth={STROKE_WIDTH}
          strokeLinecap="round"
          strokeDasharray={fullArcLen}
          style={{ strokeDashoffset: dashOffset, filter: `url(#${filterId})` }}
        />

        {/* Center: P&L value */}
        <text x={center} y={center - 10} textAnchor="middle" dominantBaseline="central"
          style={{ fill: color, fontSize: 18, fontWeight: 800, fontFamily: fonts.mono }}>
          {pnlText || '--'}
        </text>

        {/* Sub text */}
        {subText && (
          <text x={center} y={center + 10} textAnchor="middle" dominantBaseline="central"
            style={{ fill: HEX.textSecondary, fontSize: 10, fontWeight: 600, fontFamily: fonts.mono }}>
            {subText}
          </text>
        )}

        {/* Label below arc */}
        <text x={center} y={size - 4} textAnchor="middle" dominantBaseline="auto"
          style={{
            fill: color, fontSize: 10, fontWeight: 700, letterSpacing: 1.5,
            textTransform: 'uppercase', fontFamily: fonts.ui,
          }}>
          {label}
        </text>
      </svg>
    </div>
  );
}

/**
 * BotHealthGaugeRow — Renders bot gauges side by side with P&L % and color thresholds
 * Color: green >0%, amber -2% to 0%, red < -2%
 * Pass bots array from useLiveBots()
 */
export function BotHealthGaugeRow({ bots }) {
  if (!bots || bots.length === 0) return null;

  const fmt$ = (v) => {
    const n = Number(v);
    if (v == null || !isFinite(n)) return '--';
    return (n >= 0 ? '+' : '') + new Intl.NumberFormat('en-US', {
      style: 'currency', currency: 'USD', minimumFractionDigits: 0, maximumFractionDigits: 0,
    }).format(n);
  };

  const fmtPct = (v) => {
    if (v == null || !isFinite(v)) return '--';
    return `${v >= 0 ? '+' : ''}${v.toFixed(2)}%`;
  };

  // Color thresholds: green >0%, amber -2 to 0%, red < -2%
  const pnlColor = (pct) => {
    if (pct > 0) return HEX.green;
    if (pct >= -2) return HEX.amber;
    return HEX.red;
  };

  return (
    <div style={{
      display: 'flex', justifyContent: 'center', gap: 8, overflow: 'auto',
      padding: '4px 0',
    }}>
      {bots.map(bot => {
        const dayPnl = Number(bot.pnl?.day ?? bot.dayPnl) || 0;
        const equity = Number(typeof bot.equity === 'object' ? bot.equity?.current : bot.equity) || 1;
        const pnlPct = (dayPnl / equity) * 100;
        // Map -5%..+5% to 0..100 gauge fill (50 = break even)
        const gaugeVal = Math.min(100, Math.max(0, 50 + pnlPct * 10));
        const color = pnlColor(pnlPct);

        return (
          <BotHealthGauge
            key={bot.name}
            value={gaugeVal}
            label={bot.name}
            color={color}
            pnlText={fmtPct(pnlPct)}
            subText={fmt$(dayPnl)}
            size={130}
          />
        );
      })}
    </div>
  );
}
