import { useState, useEffect } from 'react'
import { api } from '../utils/api'

const COLORS = {
  bg: '#0B0F14',
  surface: '#0F1620',
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
}

const EMPTY_DIGEST = {
  date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
  bullets: [
    { text: 'Connecting to live trading data...', positive: null },
  ],
  sentiment: 'neutral',
  movers: [],
}

const sentimentColors = {
  bullish: COLORS.green,
  neutral: COLORS.blue,
  bearish: COLORS.red,
}

const sentimentLabels = {
  bullish: 'BULLISH',
  neutral: 'NEUTRAL',
  bearish: 'BEARISH',
}

function SkeletonLine({ width = '100%', height = 14 }) {
  return (
    <div
      style={{
        width,
        height,
        borderRadius: 6,
        background: `linear-gradient(90deg, ${COLORS.border} 25%, #2A3A4A 50%, ${COLORS.border} 75%)`,
        backgroundSize: '200% 100%',
        animation: 'shimmer 1.4s infinite',
      }}
    />
  )
}

export default function AIDigest() {
  const [digest, setDigest] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [lastRefreshed, setLastRefreshed] = useState(null)

  const fetchDigest = async () => {
    setLoading(true)
    setError(null)
    try {
      const data = await api('/ai/digest')
      if (!data) throw new Error('API error')
      setDigest(data)
    } catch {
      setDigest(EMPTY_DIGEST)
    } finally {
      setLoading(false)
      setLastRefreshed(new Date())
    }
  }

  useEffect(() => {
    fetchDigest()
  }, [])

  const styles = {
    card: {
      background: COLORS.surface,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 14,
      padding: '20px 24px',
      fontFamily: "'JetBrains Mono', 'Fira Code', 'Courier New', monospace",
      color: COLORS.text,
      maxWidth: 560,
      width: '100%',
    },
    header: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      marginBottom: 16,
    },
    dateText: {
      fontSize: 11,
      color: COLORS.muted,
      letterSpacing: '0.08em',
      textTransform: 'uppercase',
    },
    titleRow: {
      display: 'flex',
      alignItems: 'center',
      gap: 8,
      marginBottom: 4,
    },
    title: {
      fontSize: 14,
      fontWeight: 700,
      color: COLORS.text,
      letterSpacing: '0.04em',
    },
    aiIcon: {
      fontSize: 16,
    },
    refreshBtn: {
      background: 'transparent',
      border: `1px solid ${COLORS.border}`,
      borderRadius: 6,
      color: COLORS.muted,
      cursor: 'pointer',
      padding: '4px 10px',
      fontSize: 11,
      fontFamily: 'inherit',
      letterSpacing: '0.04em',
      transition: 'border-color 0.25s, color 0.25s',
    },
    sentimentBadge: (sentiment) => ({
      display: 'inline-block',
      background: `${sentimentColors[sentiment]}22`,
      border: `1px solid ${sentimentColors[sentiment]}55`,
      color: sentimentColors[sentiment],
      borderRadius: 6,
      fontSize: 10,
      fontWeight: 700,
      letterSpacing: '0.1em',
      padding: '2px 8px',
    }),
    divider: {
      borderTop: `1px solid ${COLORS.border}`,
      margin: '14px 0',
    },
    bulletItem: {
      display: 'flex',
      alignItems: 'flex-start',
      gap: 8,
      marginBottom: 12,
      fontSize: 13,
      lineHeight: 1.6,
    },
    bulletDot: (positive) => ({
      width: 7,
      height: 7,
      borderRadius: '50%',
      background: positive === true ? COLORS.green : positive === false ? COLORS.red : COLORS.blue,
      marginTop: 4,
      flexShrink: 0,
    }),
    bulletText: {
      color: COLORS.text,
    },
    moversRow: {
      display: 'flex',
      gap: 12,
      flexWrap: 'wrap',
    },
    moverChip: (change) => ({
      background: change >= 0 ? `${COLORS.green}18` : `${COLORS.red}18`,
      border: `1px solid ${change >= 0 ? COLORS.green : COLORS.red}44`,
      borderRadius: 6,
      padding: '4px 10px',
      fontSize: 13,
      display: 'flex',
      alignItems: 'center',
      gap: 8,
    }),
    moverSymbol: {
      color: COLORS.text,
      fontWeight: 700,
    },
    moverChange: (change) => ({
      color: change >= 0 ? COLORS.green : COLORS.red,
      fontWeight: 600,
    }),
    sectionLabel: {
      fontSize: 10,
      color: COLORS.muted,
      letterSpacing: '0.1em',
      textTransform: 'uppercase',
      marginBottom: 8,
    },
    lastRefresh: {
      fontSize: 10,
      color: COLORS.muted,
      marginTop: 12,
      textAlign: 'right',
    },
    skeletonStack: {
      display: 'flex',
      flexDirection: 'column',
      gap: 12,
    },
  }

  return (
    <div style={styles.card}>
      <style>{`
        @keyframes shimmer {
          0% { background-position: -200% 0; }
          100% { background-position: 200% 0; }
        }
        .ai-refresh-btn:hover {
          border-color: ${COLORS.blue} !important;
          color: ${COLORS.blue} !important;
        }
      `}</style>

      <div style={styles.header}>
        <div>
          <div style={styles.titleRow}>
            <span style={styles.aiIcon}>🤖</span>
            <span style={styles.title}>AI PORTFOLIO DIGEST</span>
          </div>
          {!loading && digest && (
            <div style={styles.dateText}>{String(digest.date || '')}</div>
          )}
          {loading && <SkeletonLine width={200} height={10} />}
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          {!loading && digest && digest.sentiment && (
            <div style={styles.sentimentBadge(digest.sentiment)}>
              {String(sentimentLabels[digest.sentiment] || digest.sentiment || '')}
            </div>
          )}
          <button
            className="ai-refresh-btn"
            style={styles.refreshBtn}
            onClick={fetchDigest}
            disabled={loading}
          >
            {loading ? '...' : '↻ REFRESH'}
          </button>
        </div>
      </div>

      <div style={styles.divider} />

      {loading ? (
        <div style={styles.skeletonStack}>
          <SkeletonLine width="95%" />
          <SkeletonLine width="88%" />
          <SkeletonLine width="92%" />
          <SkeletonLine width="70%" />
          <div style={{ height: 4 }} />
          <div style={{ display: 'flex', gap: 8 }}>
            <SkeletonLine width={80} height={28} />
            <SkeletonLine width={80} height={28} />
            <SkeletonLine width={80} height={28} />
          </div>
        </div>
      ) : digest ? (
        <>
          <div style={{ marginBottom: 16 }}>
            <div style={styles.sectionLabel}>Key Insights</div>
            {(Array.isArray(digest.bullets) ? digest.bullets : []).map((b, i) => (
              <div key={i} style={styles.bulletItem}>
                <div style={styles.bulletDot(b.positive)} />
                <span style={styles.bulletText}>{String(b.text || '')}</span>
              </div>
            ))}
          </div>

          <div style={styles.divider} />

          <div>
            <div style={styles.sectionLabel}>Key Movers</div>
            <div style={styles.moversRow}>
              {(Array.isArray(digest.movers) ? digest.movers : []).map((m) => (
                <div key={m.symbol} style={styles.moverChip(m.change ?? 0)}>
                  <span style={styles.moverSymbol}>{String(m.symbol || '')}</span>
                  <span style={styles.moverChange(m.change ?? 0)}>
                    {(m.change ?? 0) >= 0 ? '+' : ''}{(Number(m.change) || 0).toFixed(2)}%
                  </span>
                </div>
              ))}
            </div>
          </div>

          {lastRefreshed && (
            <div style={styles.lastRefresh}>
              Last updated {lastRefreshed.toLocaleTimeString()}
            </div>
          )}
        </>
      ) : (
        <div style={{ color: COLORS.red, fontSize: 13 }}>Failed to load digest.</div>
      )}
    </div>
  )
}
