/* ═══════════════════════════════════════════════════════════════════════════
   STREAK COUNTER
   Tracks consecutive daily logins via localStorage.
   Shows current streak with milestone celebrations at 7, 30, 100 days.
   Premium terminal aesthetic — subtle, not gamified.
   ═══════════════════════════════════════════════════════════════════════════ */
import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const mono = "'JetBrains Mono', 'SF Mono', monospace";
const body = "'Plus Jakarta Sans', -apple-system, sans-serif";

const STORAGE_KEY = 'aura_streak';
const MILESTONE_KEY = 'aura_streak_milestones_seen';

const MILESTONES = [
  { days: 7,   label: '1 Week',    tier: 'bronze' },
  { days: 14,  label: '2 Weeks',   tier: 'bronze' },
  { days: 30,  label: '1 Month',   tier: 'silver' },
  { days: 60,  label: '2 Months',  tier: 'silver' },
  { days: 100, label: '100 Days',  tier: 'gold' },
  { days: 365, label: '1 Year',    tier: 'platinum' },
];

const TIER_COLORS = {
  bronze:   { primary: '#CD7F32', glow: 'rgba(205,127,50,0.15)' },
  silver:   { primary: '#C0C0C0', glow: 'rgba(192,192,192,0.15)' },
  gold:     { primary: '#F59E0B', glow: 'rgba(245,158,11,0.2)' },
  platinum: { primary: '#A78BFA', glow: 'rgba(167,139,250,0.2)' },
};

function getToday() {
  return new Date().toISOString().slice(0, 10); // YYYY-MM-DD
}

function getYesterday() {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  return d.toISOString().slice(0, 10);
}

function loadStreak() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function saveStreak(data) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
}

function getSeenMilestones() {
  try {
    const raw = localStorage.getItem(MILESTONE_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

function markMilestoneSeen(days) {
  const seen = getSeenMilestones();
  if (!seen.includes(days)) {
    seen.push(days);
    localStorage.setItem(MILESTONE_KEY, JSON.stringify(seen));
  }
}

export default function StreakCounter() {
  const [streak, setStreak] = useState(0);
  const [longestStreak, setLongestStreak] = useState(0);
  const [milestone, setMilestone] = useState(null); // currently showing milestone
  const [showMilestone, setShowMilestone] = useState(false);

  // Initialize and update streak on mount
  useEffect(() => {
    const today = getToday();
    const yesterday = getYesterday();
    const stored = loadStreak();

    let currentStreak = 1;
    let longest = stored?.longest || 0;

    if (stored) {
      if (stored.lastDate === today) {
        // Already visited today — keep existing streak
        currentStreak = stored.count;
        longest = Math.max(longest, currentStreak);
      } else if (stored.lastDate === yesterday) {
        // Consecutive day — increment
        currentStreak = stored.count + 1;
        longest = Math.max(longest, currentStreak);
      } else {
        // Streak broken — reset to 1
        currentStreak = 1;
      }
    }

    saveStreak({ count: currentStreak, lastDate: today, longest });
    setStreak(currentStreak);
    setLongestStreak(longest);

    // Check for milestone celebrations
    const seen = getSeenMilestones();
    for (const ms of MILESTONES) {
      if (currentStreak >= ms.days && !seen.includes(ms.days)) {
        setMilestone(ms);
        setShowMilestone(true);
        markMilestoneSeen(ms.days);
        // Auto-dismiss after 5 seconds
        const t = setTimeout(() => setShowMilestone(false), 5000);
        return () => clearTimeout(t);
      }
    }
  }, []);

  // Determine the next milestone
  const nextMilestone = useMemo(() => {
    return MILESTONES.find(m => m.days > streak) || null;
  }, [streak]);

  // Current tier based on streak
  const currentTier = useMemo(() => {
    for (let i = MILESTONES.length - 1; i >= 0; i--) {
      if (streak >= MILESTONES[i].days) return MILESTONES[i].tier;
    }
    return null;
  }, [streak]);

  const tierColors = currentTier ? TIER_COLORS[currentTier] : null;
  const streakColor = tierColors?.primary || 'var(--color-amber, #F59E0B)';
  const glowColor = tierColors?.glow || 'rgba(245,158,11,0.1)';

  if (streak <= 0) return null;

  return (
    <div style={{ position: 'relative' }}>
      {/* Main streak display */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 10,
          padding: '10px 14px',
          background: glowColor,
          border: `1px solid ${streakColor}22`,
          borderRadius: 8,
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        {/* Flame icon — animated pulse for active streaks */}
        <motion.div
          animate={streak >= 7 ? {
            scale: [1, 1.1, 1],
            opacity: [0.9, 1, 0.9],
          } : {}}
          transition={streak >= 7 ? {
            duration: 2,
            repeat: Infinity,
            ease: 'easeInOut',
          } : {}}
          style={{ display: 'flex', alignItems: 'center' }}
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" style={{ filter: streak >= 30 ? `drop-shadow(0 0 4px ${streakColor})` : 'none' }}>
            <path
              d="M12 2C12 2 7 8 7 13a5 5 0 0010 0c0-5-5-11-5-11z"
              fill={streakColor}
              opacity="0.9"
            />
            <path
              d="M12 9c0 0-2.5 3-2.5 5.5a2.5 2.5 0 005 0c0-2.5-2.5-5.5-2.5-5.5z"
              fill={streak >= 30 ? '#FDE68A' : '#FCA43B'}
              opacity="0.8"
            />
          </svg>
        </motion.div>

        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: 6 }}>
            <span style={{
              fontFamily: mono,
              fontSize: 16,
              fontWeight: 800,
              color: streakColor,
              lineHeight: 1,
            }}>
              {streak}
            </span>
            <span style={{
              fontFamily: body,
              fontSize: 11,
              fontWeight: 600,
              color: 'var(--color-textPrimary, #E5E7DB)',
              lineHeight: 1,
            }}>
              day streak
            </span>
          </div>

          {/* Progress to next milestone */}
          {nextMilestone && (
            <div style={{ marginTop: 4 }}>
              <div style={{
                display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                marginBottom: 3,
              }}>
                <span style={{
                  fontFamily: mono,
                  fontSize: 9,
                  color: 'var(--color-textSecondary, #90A3AF)',
                }}>
                  {nextMilestone.days - streak} days to {nextMilestone.label}
                </span>
              </div>
              <div style={{
                width: '100%',
                height: 3,
                background: 'rgba(255,255,255,0.06)',
                borderRadius: 4,
                overflow: 'hidden',
              }}>
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${Math.min(100, (streak / nextMilestone.days) * 100)}%` }}
                  transition={{ duration: 0.8, ease: 'easeOut', delay: 0.2 }}
                  style={{
                    height: '100%',
                    background: streakColor,
                    borderRadius: 4,
                  }}
                />
              </div>
            </div>
          )}
        </div>

        {/* Longest streak badge (subtle) */}
        {longestStreak > streak && (
          <div style={{
            fontFamily: mono,
            fontSize: 9,
            color: 'var(--color-textSecondary, #90A3AF)',
            textAlign: 'right',
            opacity: 0.7,
          }}>
            Best: {longestStreak}d
          </div>
        )}
      </div>

      {/* Milestone celebration toast */}
      <AnimatePresence>
        {showMilestone && milestone && (
          <motion.div
            initial={{ opacity: 0, y: -10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -10, scale: 0.95 }}
            transition={{ duration: 0.3, ease: [0.4, 0, 0.2, 1] }}
            style={{
              position: 'absolute',
              top: 'calc(100% + 8px)',
              left: 0,
              right: 0,
              zIndex: 60,
              background: 'var(--color-surface, #0F1620)',
              border: `1px solid ${TIER_COLORS[milestone.tier]?.primary || streakColor}33`,
              borderRadius: 10,
              padding: '14px 16px',
              boxShadow: `0 8px 32px rgba(0,0,0,0.5), 0 0 20px ${TIER_COLORS[milestone.tier]?.glow || glowColor}`,
            }}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <div style={{
                width: 36, height: 36, borderRadius: '50%',
                background: `${TIER_COLORS[milestone.tier]?.primary || streakColor}18`,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                boxShadow: `0 0 12px ${TIER_COLORS[milestone.tier]?.primary || streakColor}33`,
              }}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={TIER_COLORS[milestone.tier]?.primary || streakColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
                </svg>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{
                  fontFamily: body, fontSize: 13, fontWeight: 700,
                  color: TIER_COLORS[milestone.tier]?.primary || streakColor,
                }}>
                  {milestone.label} Streak
                </div>
                <div style={{
                  fontFamily: body, fontSize: 11,
                  color: 'var(--color-textSecondary, #90A3AF)',
                  marginTop: 2,
                }}>
                  {milestone.days} consecutive days of market intelligence.
                </div>
              </div>
              <button
                onClick={() => setShowMilestone(false)}
                style={{
                  background: 'none', border: 'none', cursor: 'pointer',
                  color: 'var(--color-textSecondary, #90A3AF)',
                  padding: 4, fontSize: 16, lineHeight: 1,
                }}
                aria-label="Dismiss"
              >
                &times;
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
