import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';

/**
 * Fetches market regime, intelligence (VIX/Fear&Greed/P-C ratio),
 * allocator status, and live signals — all backend data points
 * that weren't previously wired to the frontend.
 */
export default function useMarketContext(pollMs = 120000) {  // 2 min — regime/intel change hourly
  const [regime, setRegime] = useState(null);
  const [intelligence, setIntelligence] = useState(null);
  const [allocator, setAllocator] = useState(null);
  const [signals, setSignals] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchAll = useCallback(async () => {
    const [regimeData, intelData, allocData, sigData] = await Promise.all([
      api('/regime/current', { silent: true }).catch(() => null),
      api('/market-intelligence', { silent: true }).catch(() => null),
      api('/allocator/current', { silent: true }).catch(() => null),
      api('/signals/latest', { silent: true }).catch(() => null),
    ]);

    if (regimeData && !regimeData.error) setRegime(regimeData);
    if (intelData && !intelData.error) setIntelligence(intelData);
    if (allocData && !allocData.error) setAllocator(allocData);
    if (sigData && !sigData.error) setSignals(sigData);
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchAll();
    const id = setInterval(fetchAll, pollMs);
    return () => clearInterval(id);
  }, [fetchAll, pollMs]);

  return { regime, intelligence, allocator, signals, loading };
}
