import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import { motion } from 'framer-motion';

const TIER_THRESHOLDS = { rookie: 0, trader: 500, veteran: 2000, elite: 5000, legend: 15000 };
const TIER_ORDER = ['rookie', 'trader', 'veteran', 'elite', 'legend'];

export default function DailyEngagementWidget() {
  const [profile, setProfile] = useState(null);
  const [rankData, setRankData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    (async () => {
      try {
        const [p, r] = await Promise.all([
          api('/gamification/profile', { silent: true }).catch(() => null),
          api('/rankings/me', { silent: true }).catch(() => null),
        ]);
        setProfile(p);
        setRankData(r);
      } catch {}
    })();
  }, []);

  // Hide widget entirely when gamification data isn't available.
  // Both API calls may return null (404) or empty default objects with zeros —
  // either way, don't show a widget full of placeholder values.
  const hasProfileData = profile && (profile.xp > 0 || (profile.tier && profile.tier !== 'rookie') || profile.streak_days > 0);
  const hasRankData = rankData && rankData.rank != null;
  if (!hasProfileData && !hasRankData) return null;

  const xp = profile?.xp || 0;
  const tierRaw = profile?.tier || 'rookie';
  const tier = typeof tierRaw === 'object' ? (tierRaw.current_tier || tierRaw.name || 'rookie') : tierRaw;
  const tierIdx = TIER_ORDER.indexOf(tier);
  const nextTier = tierIdx < TIER_ORDER.length - 1 ? TIER_ORDER[tierIdx + 1] : null;
  const nextThreshold = nextTier ? TIER_THRESHOLDS[nextTier] : xp;
  const currentThreshold = TIER_THRESHOLDS[tier] || 0;
  const progress = nextTier ? Math.min(((xp - currentThreshold) / (nextThreshold - currentThreshold)) * 100, 100) : 100;
  const streak = profile?.streak_days || 0;
  const delta = rankData?.delta || 0;

  const cardStyle = {
    display: 'flex', gap: 16, padding: '10px 16px', background: '#161B22',
    border: '1px solid #30363D', borderRadius: 10, alignItems: 'center', flexWrap: 'wrap',
  };
  const metricStyle = { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2, cursor: 'pointer', minWidth: 70 };
  const labelStyle = { fontSize: 10, color: '#8B949E', textTransform: 'uppercase', letterSpacing: 0.5 };
  const valueStyle = { fontSize: 16, fontWeight: 700, fontFamily: "'JetBrains Mono', monospace" };

  return (
    <div style={cardStyle}>
      {/* Rank Change */}
      <div style={metricStyle} onClick={() => navigate('/leaderboard')}>
        <span style={labelStyle}>Rank</span>
        <span style={{ ...valueStyle, color: delta > 0 ? '#3FB950' : delta < 0 ? '#F85149' : '#8B949E' }}>
          {rankData?.rank ? `#${rankData.rank}` : '-'}
          {delta !== 0 && <span style={{ fontSize: 11, marginLeft: 2 }}>{delta > 0 ? `+${delta}` : delta}</span>}
        </span>
      </div>

      {/* Streak */}
      <div style={metricStyle} onClick={() => navigate('/achievements')}>
        <span style={labelStyle}>Streak</span>
        <span style={{ ...valueStyle, color: streak >= 7 ? '#D29922' : streak >= 3 ? '#3FB950' : '#E6EDF3' }}>
          {streak}d
        </span>
      </div>

      {/* XP */}
      <div style={metricStyle} onClick={() => navigate('/achievements')}>
        <span style={labelStyle}>XP</span>
        <span style={{ ...valueStyle, color: '#BC8CFF' }}>{xp.toLocaleString()}</span>
      </div>

      {/* Tier Progress */}
      <div style={{ ...metricStyle, flex: 1, minWidth: 120, alignItems: 'stretch' }} onClick={() => navigate('/achievements')}>
        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
          <span style={labelStyle}>{tier}</span>
          {nextTier && <span style={{ ...labelStyle, color: '#58A6FF' }}>{nextTier}</span>}
        </div>
        <div style={{ height: 6, background: '#30363D', borderRadius: 3, overflow: 'hidden' }}>
          <motion.div
            style={{ height: '100%', background: '#58A6FF', borderRadius: 3 }}
            initial={{ width: 0 }}
            animate={{ width: `${progress}%` }}
            transition={{ duration: 0.8, ease: 'easeOut' }}
          />
        </div>
      </div>
    </div>
  );
}
