// ─── Helpers ────────────────────────────────────────────────────────────────

function fmt$(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return '—';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2 }).format(n);
}

function fmtPnl(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return { value: '—', color: '#90A3AF' };
  return { value: (n >= 0 ? '+' : '') + fmt$(n), color: n >= 0 ? '#22C55E' : '#EF4444' };
}

// Safe-string helper: ensures value is always a primitive string for JSX rendering
function S(v) {
  if (v == null) return '—';
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

function getMarketStatus() {
  const now = new Date();
  // Safari-safe ET conversion — avoid new Date(toLocaleString()) which breaks on Safari
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York', hour: 'numeric', minute: 'numeric', weekday: 'short', hour12: false,
  }).formatToParts(now);
  const get = (type) => parts.find(p => p.type === type)?.value || '';
  const dayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const day = dayMap[get('weekday')] ?? now.getDay();
  const h = parseInt(get('hour'), 10) || 0;
  const m = parseInt(get('minute'), 10) || 0;
  const t = h * 60 + m;
  if (day === 0 || day === 6) return { label: 'WEEKEND', isOpen: false, color: HEX.textSecondary };
  if (t >= 570 && t < 960) return { label: 'MARKET OPEN', isOpen: true, color: HEX.green };
  if (t >= 240 && t < 570) return { label: 'PRE-MARKET', isOpen: false, color: HEX.blue };
  return { label: 'AFTER HOURS', isOpen: false, color: HEX.amber };
}

// ─── Animated count-up for hero gauge numbers ─────────────────────────────
function AnimatedValue({ value, format = 'number', duration = 1000 }) {
  const initialDisplay = format === 'dollar' ? fmt$(0) : format === 'int' ? 0 : format === 'percent' ? '+0.00%' : 0;
  const [display, setDisplay] = React.useState(initialDisplay);
  const prevRef = useRef(0);
  const rafRef = useRef(null);

  useEffect(() => {
    const target = Number(value);
    if (!isFinite(target)) { setDisplay(value); return; }
    const start = prevRef.current;
    const delta = target - start;
    if (delta === 0) {
      if (format === 'dollar') setDisplay(fmt$(target));
      else if (format === 'percent') setDisplay(`${target >= 0 ? '+' : ''}${target.toFixed(2)}%`);
      else if (format === 'int') setDisplay(Math.round(target));
      else setDisplay(Number(target.toFixed(1)));
      return;
    }
    const t0 = performance.now();
    const tick = (now) => {
      const p = Math.min((now - t0) / duration, 1);
      const ease = 1 - Math.pow(1 - p, 3); // ease-out cubic
      const current = start + delta * ease;
      if (format === 'dollar') {
        setDisplay(fmt$(current));
      } else if (format === 'percent') {
        setDisplay(`${current >= 0 ? '+' : ''}${current.toFixed(2)}%`);
      } else if (format === 'int') {
        setDisplay(Math.round(current));
      } else {
        setDisplay(Number(current.toFixed(1)));
      }
      if (p < 1) rafRef.current = requestAnimationFrame(tick);
      else prevRef.current = target;
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => { if (rafRef.current) cancelAnimationFrame(rafRef.current); };
  }, [value, format, duration]);

  return <>{display}</>;
}

// ─── usePnlSummary hook ──────────────────────────────────────────────────────

function usePnlSummary() {
  const [data, setData] = React.useState(null);
  const [loading, setLoading] = React.useState(true);
  useEffect(() => {
    let cancelled = false;
    async function load() {
      try {
        const res = await api('/pnl/summary');
        if (!cancelled) { setData(res); setLoading(false); }
      } catch {
        if (!cancelled) setLoading(false);
      }
    }
    load();
    const id = setInterval(load, 30000);
    return () => { cancelled = true; clearInterval(id); };
  }, []);
  return { data, loading };
}

