function fmtPct(pnl, equity) {
  const p = Number(pnl), e = Number(equity);
  if (!isFinite(p) || !isFinite(e)) return '';
  const base = e - p;
  if (base <= 0) return '';
  return `(${p >= 0 ? '+' : ''}${((p / base) * 100).toFixed(2)}%)`;
}

