// ─── Equity Curve (combined all bots) ───────────────────────────────────────

// Catmull-Rom spline → SVG cubic bezier path for smooth curves
function smoothPath(pts) {
  if (pts.length < 2) return '';
  if (pts.length === 2) return `M${pts[0].x},${pts[0].y}L${pts[1].x},${pts[1].y}`;

  const tension = 0.3;
  let d = `M${pts[0].x},${pts[0].y}`;
  for (let i = 0; i < pts.length - 1; i++) {
    const p0 = pts[Math.max(0, i - 1)];
    const p1 = pts[i];
    const p2 = pts[i + 1];
    const p3 = pts[Math.min(pts.length - 1, i + 2)];

    const cp1x = p1.x + (p2.x - p0.x) * tension;
    const cp1y = p1.y + (p2.y - p0.y) * tension;
    const cp2x = p2.x - (p3.x - p1.x) * tension;
    const cp2y = p2.y - (p3.y - p1.y) * tension;

    d += `C${cp1x},${cp1y},${cp2x},${cp2y},${p2.x},${p2.y}`;
  }
  return d;
}

function EquityCurveWidget({ bots, selectedBot }) {
  const containerRef = useRef(null);
  const pathRef = useRef(null);
  const fillRef = useRef(null);
  const [dims, setDims] = useState({ w: 660, h: 140 });
  const [drawn, setDrawn] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const ro = new ResizeObserver(entries => {
      for (const e of entries) setDims({ w: e.contentRect.width, h: e.contentRect.height });
    });
    ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, []);

  // Filter to selected bot or merge all bots (memoized to avoid re-render churn)
  const filteredBots = useMemo(() =>
    selectedBot ? (bots || []).filter(b => b.name === selectedBot) : (bots || []),
    [bots, selectedBot]
  );

  // Merge equity curves from all bots into a combined timeline
  // Bucket timestamps to nearest hour so multi-bot points align
  const BUCKET = 3600; // 1 hour buckets
  const buckets = {};
  filteredBots.forEach(bot => {
    (bot.equityCurve || []).forEach(p => {
      const key = Math.round(p.ts / BUCKET) * BUCKET;
      if (!buckets[key]) buckets[key] = {};
      buckets[key][bot.name] = (p.value || 0);
    });
  });

  // For each bucket, sum all bots' latest known value
  const botNames = filteredBots.map(b => b.name);
  const sortedKeys = Object.keys(buckets).map(Number).sort((a, b) => a - b);
  const lastKnown = {};
  const combined = [];
  for (const ts of sortedKeys) {
    const snap = buckets[ts];
    // Forward-fill: use latest known value for each bot
    for (const name of botNames) {
      if (snap[name] != null) lastKnown[name] = snap[name];
    }
    const total = botNames.reduce((s, name) => s + (lastKnown[name] || 0), 0);
    if (total > 0) combined.push({ ts, value: total });
  }

  // Downsample to max ~120 points for smooth rendering
  const MAX_PTS = 120;
  let data = combined;
  if (data.length > MAX_PTS) {
    const step = data.length / MAX_PTS;
    data = Array.from({ length: MAX_PTS }, (_, i) => data[Math.floor(i * step)]);
    // Always include the last point
    if (combined.length > 0) data[data.length - 1] = combined[combined.length - 1];
  }

  // Draw-on animation: measure path and animate stroke-dashoffset
  useEffect(() => {
    if (data.length < 2) return;
    setDrawn(false);
    const timer = requestAnimationFrame(() => {
      if (pathRef.current) {
        const len = pathRef.current.getTotalLength();
        pathRef.current.style.strokeDasharray = `${len}`;
        pathRef.current.style.strokeDashoffset = `${len}`;
        // Trigger reflow, then animate
        pathRef.current.getBoundingClientRect();
        pathRef.current.style.transition = 'stroke-dashoffset 1.2s cubic-bezier(0.16,1,0.3,1)';
        pathRef.current.style.strokeDashoffset = '0';
      }
      if (fillRef.current) {
        fillRef.current.style.opacity = '0';
        fillRef.current.getBoundingClientRect();
        fillRef.current.style.transition = 'opacity 0.8s ease 0.4s';
        fillRef.current.style.opacity = '1';
      }
      setDrawn(true);
    });
    return () => cancelAnimationFrame(timer);
  }, [data.length, selectedBot]);

  if (data.length < 2) {
    return (
      <div ref={containerRef} className={s.equityCurve_empty}>
        <span className={s.equityCurve_emptyText}>
          Your equity curve will appear here once your bots start trading. Deploy a strategy from the Leaderboard to get started.
        </span>
        <a href="/leaderboard" style={{
          fontFamily: mono, fontSize: 12, fontWeight: 600, color: HEX.blue,
          textDecoration: 'none', marginTop: 8, display: 'inline-block',
        }}>
          Browse Strategies &rarr;
        </a>
      </div>
    );
  }

  const values = data.map(d => d.value);
  const max = Math.max(...values);
  // Auto-scale: ignore outlier lows (pre-deposit near-zero) for Y-axis range
  // Use meaningful values (>=10% of max) to set the floor, so actual trading range fills the chart
  const meaningfulVals = values.filter(v => v >= max * 0.1);
  const min = meaningfulVals.length > 0 ? Math.min(...meaningfulVals) : Math.min(...values);
  const range = max - min || 1;
  const { w, h } = dims;
  const padTop = 8, padBot = 20;
  const chartH = h - padBot;

  // Clamp values to the visible range so outlier lows don't blow the scale
  const toY = v => chartH - ((Math.max(v, min) - min) / range) * (chartH - padTop);
  const toX = (i) => (i / (values.length - 1)) * w;

  // Build smooth path points
  const pts = values.map((v, i) => ({ x: toX(i), y: toY(v) }));
  const curvePath = smoothPath(pts);

  // Compute market regime zones from equity curve slope (bull/bear/neutral shading)
  const zones = [];
  if (pts.length >= 3) {
    let zoneStart = 0;
    for (let i = 1; i < pts.length; i++) {
      const slope = pts[i].y - pts[i - 1].y; // negative y = price up in SVG coords
      const prevSlope = i > 1 ? pts[i - 1].y - pts[i - 2].y : slope;
      const dirChanged = (slope < 0 && prevSlope >= 0) || (slope >= 0 && prevSlope < 0);
      if (dirChanged || i === pts.length - 1) {
        const end = i === pts.length - 1 ? i : i;
        const seg = pts.slice(zoneStart, end + 1);
        const avgSlope = seg.length > 1
          ? seg.reduce((s, p, j, arr) => j > 0 ? s + (p.y - arr[j - 1].y) : s, 0) / (seg.length - 1)
          : 0;
        zones.push({
          x1: pts[zoneStart].x,
          x2: pts[Math.min(end, pts.length - 1)].x,
          regime: avgSlope < -1 ? 'bullish' : avgSlope > 1 ? 'bearish' : 'neutral',
        });
        zoneStart = i;
      }
    }
  }

  // Polygon fill (area under curve) — use polyline for fill compatibility
  const fillPoints = pts.map(p => `${p.x},${p.y}`).join(' ');

  const lastVal = values[values.length - 1];
  // Use first meaningful equity value as baseline (skip near-zero pre-deposit points)
  // "Meaningful" = at least 10% of the current value, avoids absurd % from $0.01 → $1159
  const threshold = lastVal * 0.1;
  const firstVal = values.find(v => v >= threshold) ?? values[0];
  const trend = lastVal >= firstVal ? HEX.green : HEX.red;
  const changePct = firstVal > 0 ? (((lastVal - firstVal) / firstVal) * 100).toFixed(2) : '0.00';

  const fmtTs = ts => {
    const d = new Date(ts * 1000);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  return (
    <div ref={containerRef} className={s.equityCurve_container}>
      <svg width={w} height={h} className={s.equityCurve_svg} role="img" aria-label="Portfolio equity curve chart">
        <defs>
          <linearGradient id="eqGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={trend} stopOpacity="0.30" />
            <stop offset="60%" stopColor={trend} stopOpacity="0.08" />
            <stop offset="100%" stopColor={trend} stopOpacity="0.01" />
          </linearGradient>
          <filter id="curveGlow">
            <feDropShadow dx="0" dy="0" stdDeviation="3" floodColor={trend} floodOpacity="0.4" />
          </filter>
          <filter id="dotGlow">
            <feDropShadow dx="0" dy="0" stdDeviation="4" floodColor={trend} floodOpacity="0.6" />
          </filter>
        </defs>
        <style>{`
          @keyframes eqPulse {
            0%, 100% { r: 3; opacity: 1; }
            50% { r: 5; opacity: 0.7; }
          }
          @keyframes eqRingPulse {
            0%, 100% { r: 7; opacity: 0.25; }
            50% { r: 12; opacity: 0; }
          }
          .eq-dot-core { animation: eqPulse 2s ease-in-out infinite; }
          .eq-dot-ring { animation: eqRingPulse 2s ease-in-out infinite; }
        `}</style>
        {/* Market regime background shading */}
        {zones.map((z, i) => (
          <rect key={`rz${i}`} x={z.x1} y={0} width={Math.max(0, z.x2 - z.x1)} height={chartH}
            fill={z.regime === 'bullish' ? HEX.green : z.regime === 'bearish' ? HEX.red : HEX.blue}
            opacity={0.05} rx="2" />
        ))}
        {/* Regime legend — centered below top labels to avoid overlap */}
        {zones.length > 0 && (
          <g transform={`translate(${Math.max(4, (w - 140) / 2)}, ${padTop + 14})`}>
            <rect width="8" height="8" rx="2" fill={HEX.green} opacity="0.3" />
            <text x="12" y="7" fill={HEX.textSecondary} fontSize="7" fontFamily={mono}>Bull</text>
            <rect x="38" width="8" height="8" rx="2" fill={HEX.blue} opacity="0.3" />
            <text x="50" y="7" fill={HEX.textSecondary} fontSize="7" fontFamily={mono}>Neutral</text>
            <rect x="84" width="8" height="8" rx="2" fill={HEX.red} opacity="0.3" />
            <text x="96" y="7" fill={HEX.textSecondary} fontSize="7" fontFamily={mono}>Bear</text>
          </g>
        )}
        {/* Grid lines */}
        {[0.25, 0.5, 0.75].map(pct => (
          <line key={pct} x1={0} x2={w} y1={toY(min + range * pct)} y2={toY(min + range * pct)}
            stroke={HEX.border} strokeWidth="0.5" strokeDasharray="3,3" />
        ))}
        {/* Filled area (fades in after draw-on) */}
        <polygon ref={fillRef} points={`0,${chartH} ${fillPoints} ${w},${chartH}`} fill="url(#eqGrad)" />
        {/* Smooth curve with glow + draw-on animation */}
        <path ref={pathRef} d={curvePath} fill="none" stroke={trend} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" filter="url(#curveGlow)" />
        {/* End dot with pulsing glow animation */}
        <circle className="eq-dot-ring" cx={pts[pts.length - 1].x} cy={pts[pts.length - 1].y} r="7" fill={trend} opacity="0.25" filter="url(#dotGlow)" />
        <circle className="eq-dot-core" cx={pts[pts.length - 1].x} cy={pts[pts.length - 1].y} r="3" fill={trend} filter="url(#dotGlow)" />
        {/* Labels */}
        <text x={4} y={h - 4} fill={HEX.textSecondary} fontSize="9" fontFamily={mono}>{fmtTs(data[0].ts)}</text>
        <text x={w - 4} y={h - 4} fill={HEX.textSecondary} fontSize="9" fontFamily={mono} textAnchor="end">{fmtTs(data[data.length - 1].ts)}</text>
        <text x={w - 4} y={14} fill={trend} fontSize="11" fontFamily={mono} textAnchor="end" fontWeight="700">
          {lastVal >= firstVal ? '+' : ''}{changePct}%
        </text>
        <text x={4} y={14} fill={HEX.textPrimary} fontSize="11" fontFamily={mono} fontWeight="700">
          {fmt$(lastVal)}
        </text>
      </svg>
    </div>
  );
}

// ─── Market Context Bar ─────────────────────────────────────────────────────

const MarketContextBar = React.memo(function MarketContextBar({ regime, intelligence, allocator, signals }) {
  if (!regime && !intelligence && !signals) return null;

  const pills = [];

  // Regime
  if (regime) {
    const regimeLabel = (regime.regime || regime.current || '').replace(/_/g, ' ');
    const conf = regime.confidence != null ? `${(regime.confidence * 100).toFixed(0)}%` : '';
    const regimeColor = regimeLabel.includes('bull') || regimeLabel.includes('trending up') ? tokens.color.green
      : regimeLabel.includes('bear') || regimeLabel.includes('trending down') ? tokens.color.red
      : tokens.color.blue;
    pills.push({ label: 'Regime', value: regimeLabel, sub: conf, color: regimeColor });
  }

  // VIX (may be nested: { level, ma20, regime } or flat number)
  const vixRaw = intelligence?.vix;
  const vixVal = typeof vixRaw === 'object' ? vixRaw?.level : vixRaw;
  if (vixVal != null) {
    const vix = Number(vixVal);
    const vixColor = vix > 30 ? tokens.color.red : vix > 20 ? tokens.color.amber : tokens.color.green;
    const vixTrend = typeof vixRaw === 'object' ? vixRaw.trend : null;
    pills.push({ label: 'VIX', value: vix.toFixed(1), sub: vixTrend, color: vixColor });
  }

  // Fear & Greed (may be nested or flat)
  const fgRaw = intelligence?.fear_and_greed ?? intelligence?.fear_greed;
  const fgVal = typeof fgRaw === 'object' ? fgRaw?.value : fgRaw;
  if (fgVal != null) {
    const fg = Number(fgVal);
    const fgColor = fg < 25 ? tokens.color.red : fg < 45 ? tokens.color.amber : fg > 75 ? tokens.color.green : tokens.color.blue;
    const fgLabel = fg < 25 ? 'Extreme Fear' : fg < 45 ? 'Fear' : fg > 75 ? 'Extreme Greed' : fg > 55 ? 'Greed' : 'Neutral';
    pills.push({ label: 'F&G', value: `${fg.toFixed(0)}`, sub: fgLabel, color: fgColor });
  }

  // Put/Call Ratio (may be nested: { estimated_ratio, sentiment })
  const pcRaw = intelligence?.put_call_ratio;
  const pcVal = typeof pcRaw === 'object' ? pcRaw?.estimated_ratio ?? pcRaw?.ratio : pcRaw;
  if (pcVal != null) {
    const pc = Number(pcVal);
    const pcColor = pc > 1.2 ? tokens.color.red : pc < 0.7 ? tokens.color.green : tokens.color.blue;
    const pcSentiment = typeof pcRaw === 'object' ? pcRaw.sentiment : null;
    pills.push({ label: 'P/C', value: pc.toFixed(2), sub: pcSentiment, color: pcColor });
  }

  // FOMC countdown
  if (intelligence?.fomc?.days_until != null) {
    const days = intelligence.fomc.days_until;
    if (days <= 7) {
      pills.push({ label: 'FOMC', value: `${days}d`, color: days <= 2 ? tokens.color.red : tokens.color.amber });
    }
  }

  // Live signals count
  if (signals) {
    const sigCount = Array.isArray(signals) ? signals.length
      : Array.isArray(signals.signals) ? signals.signals.length
      : signals.count ?? 0;
    if (sigCount > 0) {
      pills.push({ label: 'Signals', value: String(sigCount), color: tokens.color.cyan });
    }
  }

  // Allocator
  if (allocator?.bots) {
    const botNames = Object.keys(allocator.bots);
    const alloc = botNames.map(n => `${n.charAt(0).toUpperCase() + n.slice(1)} ${allocator.bots[n]?.allocation_pct ?? '?'}%`).join(' / ');
    pills.push({ label: 'Allocation', value: alloc, color: tokens.color.purple });
  }

  if (pills.length === 0) return null;

  return (
    <div className={s.marketBar}>
      {pills.map(p => (
        <div key={p.label} className={s.marketPill}>
          <span className={s.marketPill_label}>{p.label}</span>
          <span className={s.marketPill_value} style={{ color: p.color }}>{p.value}</span>
          {p.sub && <span className={s.marketPill_sub}>{p.sub}</span>}
        </div>
      ))}
    </div>
  );
});

// ─── KPI Tiles ──────────────────────────────────────────────────────────────

const KPITiles = React.memo(function KPITiles({ bots, risk }) {
  const safeBots = Array.isArray(bots) ? bots : [];
  const liveBots = safeBots.filter(b => b?.mode?.toLowerCase() !== 'paper');
  const totalEquity = liveBots.reduce((s, b) => s + (b?.equity || 0), 0);
  const dayPnl = liveBots.reduce((s, b) => s + (b?.pnl?.day || 0), 0);
  const weekPnl = liveBots.reduce((s, b) => s + (b?.pnl?.week || 0), 0);
  const monthPnl = liveBots.reduce((s, b) => s + (b?.pnl?.month || 0), 0);
  const exposure = risk?.totalExposure || 0;
  const kpiRiskBots = Array.isArray(risk?.bots) ? risk.bots : [];
  const botBP = liveBots.reduce((s, b) => s + (b?.buyingPower ?? 0), 0);
  const buyingPower = botBP > 0 ? botBP : kpiRiskBots.reduce((s, b) => s + (b.buying_power ?? 0), 0);
  const heat = Number(risk?.portfolioHeat) || 0;

  const tiles = [
    { label: 'Total Equity', value: fmt$(totalEquity), color: tokens.color.text, trend: 'neutral', accent: tokens.color.cyan },
    { label: 'Day P&L', ...fmtPnl(dayPnl), trend: dayPnl >= 0 ? 'up' : 'down' },
    { label: 'Week P&L', ...fmtPnl(weekPnl), trend: weekPnl >= 0 ? 'up' : 'down' },
    { label: 'Month P&L', ...fmtPnl(monthPnl), trend: monthPnl >= 0 ? 'up' : 'down' },
    { label: 'Exposure', value: exposure === 0 ? '\u2014' : fmt$(exposure), color: tokens.color.blue, trend: 'neutral', accent: tokens.color.blue },
    { label: 'Buying Power', value: fmt$(buyingPower), color: tokens.color.purple, trend: 'neutral', accent: tokens.color.purple },
    { label: 'Portfolio Heat', value: `${heat.toFixed(1)}%`, color: heat > 80 ? tokens.color.red : heat > 50 ? tokens.color.amber : tokens.color.green, trend: heat > 50 ? 'down' : 'up', accent: heat > 50 ? tokens.color.red : tokens.color.green },
  ];

  return (
    <div className={s.kpiGrid}>
      {tiles.map(t => (
        <div key={t.label} className={s.kpiTile}>
          <StatCard
            label={<>{t.label}<InfoTooltip term={t.label} size={11} /></>}
            value={t.value}
            color={t.color}
            trend={t.trend}
            accentColor={t.accent}
            compact
          />
        </div>
      ))}
    </div>
  );
});

// ─── Candlestick Chart (TradingView Lightweight Charts) ─────────────────────

function CandlestickChart({ chartData, loading, error, symbol, onSymbolChange }) {
  const containerRef = useRef(null);
  const chartRef = useRef(null);

  useEffect(() => {
    if (!containerRef.current) return;
    if (chartRef.current) { try { chartRef.current.remove(); } catch {} chartRef.current = null; }
    if (!chartData) return;

    try {
    const isTouchDevice = typeof window !== 'undefined' && window.innerWidth <= 1024;
    const chart = createChart(containerRef.current, {
      width: containerRef.current.clientWidth,
      height: containerRef.current.clientHeight,
      layout: { background: { type: ColorType.Solid, color: HEX.surface2 }, textColor: HEX.textSecondary, fontFamily: mono, fontSize: isTouchDevice ? 9 : 10 },
      grid: { vertLines: { color: HEX.border + '40' }, horzLines: { color: HEX.border + '40' } },
      crosshair: { mode: isTouchDevice ? CrosshairMode.Magnet : CrosshairMode.Normal },
      rightPriceScale: { borderColor: HEX.border },
      timeScale: { borderColor: HEX.border, timeVisible: true },
      handleScroll: { vertTouchDrag: false, horzTouchDrag: true },
      handleScale: { pinch: true },
    });
    chartRef.current = chart;

    const rawBars = chartData?.bars || chartData?.data || [];
    const bars = Array.isArray(rawBars) ? rawBars : [];
    if (bars.length > 0) {
      const series = chart.addSeries(CandlestickSeries, {
        upColor: HEX.green, downColor: HEX.red,
        borderUpColor: HEX.green, borderDownColor: HEX.red,
        wickUpColor: HEX.green, wickDownColor: HEX.red,
      });
      const mapped = bars.map(b => ({
        time: typeof b.time === 'number' ? b.time : b.date || b.time,
        open: b.open, high: b.high, low: b.low, close: b.close,
      })).sort((a, b) => (a.time < b.time ? -1 : 1));
      series.setData(mapped);
      chart.timeScale().fitContent();
    }

    const ro = new ResizeObserver(entries => {
      for (const e of entries) chart.resize(e.contentRect.width, e.contentRect.height);
    });
    ro.observe(containerRef.current);
    return () => { ro.disconnect(); try { chart.remove(); } catch {} };
    } catch (err) {
      console.error('Chart creation failed:', err);
    }
  }, [chartData]);

  return (
    <div className={s.chart_wrapper}>
      <div className={s.chart_toolbar}>
        <input
          type="text"
          value={symbol}
          onChange={e => onSymbolChange(e.target.value.toUpperCase())}
          onKeyDown={e => { if (e.key === 'Enter') e.target.blur(); }}
          className={s.chart_symbolInput}
          placeholder="AAPL"
        />
        {loading && <SkeletonMetricRow count={2} />}
        {error && <span className={s.chart_errorText}>{typeof error === 'string' ? error : String(error?.message || 'An error occurred')}</span>}
      </div>
      <div ref={containerRef} className={s.chart_container}>
        {!chartData && !loading && (
          <div className={s.chart_emptyInner}>
            <span className={s.chart_emptyText}>
              Enter a symbol above
            </span>
          </div>
        )}
        {/* Aura Alpha watermark */}
        <img
          src="/images/logo-main.webp"
          alt=""
          loading="lazy"
          decoding="async"
          className={s.chart_watermark}
        />
      </div>
    </div>
  );
}

