// ─── Alert Toast Popup — only shows when alerts actually fire ────────────────

function AlertToasts({ triggered }) {
  const [dismissed, setDismissed] = useState(new Set());
  const [seenIds, setSeenIds] = useState(new Set());

  // Track which alerts are "new" (appeared after initial load)
  const items = (triggered || []).filter(a => {
    const id = a.id || `${a.symbol}-${a.condition}-${a.price}`;
    return !dismissed.has(id);
  });

  // Auto-dismiss after 15 seconds
  useEffect(() => {
    if (items.length === 0) return;
    const timer = setTimeout(() => {
      setDismissed(prev => {
        const next = new Set(prev);
        items.forEach(a => next.add(a.id || `${a.symbol}-${a.condition}-${a.price}`));
        return next;
      });
    }, 15000);
    return () => clearTimeout(timer);
  }, [items]);

  if (items.length === 0) return null;

  return (
    <div className={s.alertToast_container}>
      {items.slice(0, 5).map((a, i) => {
        const id = a.id || `${a.symbol}-${a.condition}-${a.price}`;
        return (
          <div key={id} className={s.alertToast_card}>
            <div className={s.alertToast_body}>
              <div className={s.alertToast_header}>
                <span className={s.alertToast_badge}>Alert Triggered</span>
              </div>
              <div className={s.alertToast_symbol}>
                {S(a.symbol || '--')}
              </div>
              <div className={s.alertToast_condition}>
                {S(a.condition || a.type || 'Price alert')} {a.price ? `@ $${a.price}` : ''}
              </div>
            </div>
            <button
              onClick={() => setDismissed(prev => new Set(prev).add(id))}
              className={s.alertToast_dismiss}
            >×</button>
          </div>
        );
      })}
    </div>
  );
}

