// ─── Market Status Banner (with countdown to open/close) ─────────────────────

function getNextMarketEvent() {
  const now = new Date();
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York', hour: 'numeric', minute: 'numeric',
    second: 'numeric', weekday: 'short', hour12: false,
  }).formatToParts(now);
  const get = (type) => parts.find(p => p.type === type)?.value || '';
  const dayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const day = dayMap[get('weekday')] ?? now.getDay();
  const h = parseInt(get('hour'), 10) || 0;
  const m = parseInt(get('minute'), 10) || 0;
  const s = parseInt(get('second'), 10) || 0;
  const totalSec = h * 3600 + m * 60 + s;
  const openSec = 9 * 3600 + 30 * 60;   // 9:30 AM ET
  const closeSec = 16 * 3600;            // 4:00 PM ET

  if (day >= 1 && day <= 5 && totalSec >= openSec && totalSec < closeSec) {
    // Market is open -> countdown to close
    const remaining = closeSec - totalSec;
    return { isOpen: true, label: 'MARKET OPEN', event: 'Close', remaining, color: '#22C55E' };
  }
  // Market is closed -> countdown to next open
  let secsUntilOpen = 0;
  if (day >= 1 && day <= 5 && totalSec < openSec) {
    secsUntilOpen = openSec - totalSec;
  } else if (day === 5 && totalSec >= closeSec) {
    secsUntilOpen = (2 * 86400) + openSec + (86400 - totalSec); // to Monday
  } else if (day === 6) {
    secsUntilOpen = 86400 + openSec + (86400 - totalSec); // to Monday
  } else if (day === 0) {
    secsUntilOpen = openSec + (86400 - totalSec); // to Monday
  } else {
    secsUntilOpen = openSec + (86400 - totalSec); // next day
  }
  const isWeekend = day === 0 || day === 6;
  const isPreMarket = day >= 1 && day <= 5 && totalSec >= 4 * 3600 && totalSec < openSec;
  const isAfterHours = day >= 1 && day <= 5 && totalSec >= closeSec && totalSec < 20 * 3600;
  const label = isWeekend ? 'WEEKEND' : isPreMarket ? 'PRE-MARKET' : isAfterHours ? 'AFTER HOURS' : 'CLOSED';
  const color = isPreMarket ? '#60A5FA' : isAfterHours ? '#F59E0B' : '#8B949E';
  return { isOpen: false, label, event: 'Open', remaining: secsUntilOpen, color };
}

function formatCountdown(secs) {
  if (secs <= 0) return '00:00:00';
  const h = Math.floor(secs / 3600);
  const m = Math.floor((secs % 3600) / 60);
  const s = secs % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

function MarketStatusBanner() {
  const [mkt, setMkt] = useState(getNextMarketEvent);

  useEffect(() => {
    const id = setInterval(() => setMkt(getNextMarketEvent()), 1000);
    return () => clearInterval(id);
  }, []);

  return (
    <div className={s.mktBanner} style={{ borderColor: `${mkt.color}30` }}>
      <div className={s.mktBanner_left}>
        <span className={s.mktBanner_dot} style={{ background: mkt.color, boxShadow: `0 0 8px ${mkt.color}60` }} />
        <span className={s.mktBanner_label} style={{ color: mkt.color }}>{mkt.label}</span>
      </div>
      <div className={s.mktBanner_right}>
        <span className={s.mktBanner_eventLabel}>{mkt.event} in</span>
        <span className={s.mktBanner_countdown} style={{ color: mkt.color }}>
          {formatCountdown(mkt.remaining)}
        </span>
      </div>
    </div>
  );
}

