// ─── Top Movers Widget ──────────────────────────────────────────────────────

function TopMoversWidget() {
  const [movers, setMovers] = useState({ gainers: [], losers: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const fetchMovers = async () => {
      try {
        let data;
        try {
          data = await api('/scanners/momentum_breakout', { silent: true });
        } catch {
          try { data = await api('/scanners/signals/live', { silent: true }); } catch { data = null; }
        }
        if (cancelled || !data) return;
        const list = Array.isArray(data) ? data
          : Array.isArray(data?.signals) ? data.signals
          : Array.isArray(data?.data) ? data.data
          : [];
        // Sort by change percent
        const withChange = list.map(item => ({
          symbol: item.symbol || item.ticker || '--',
          change: Number(item.change_pct ?? item.pct_change ?? item.change ?? item.score ?? 0),
          price: Number(item.price ?? item.close ?? item.last ?? 0),
        })).filter(x => x.symbol !== '--');
        const sorted = [...withChange].sort((a, b) => b.change - a.change);
        const gainers = sorted.filter(x => x.change > 0).slice(0, 5);
        const losers = [...withChange].sort((a, b) => a.change - b.change).filter(x => x.change < 0).slice(0, 5);
        if (!cancelled) setMovers({ gainers, losers });
      } catch {
        // silently fail
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    fetchMovers();
    const iv = setInterval(fetchMovers, 60000);
    return () => { cancelled = true; clearInterval(iv); };
  }, []);

  const [tab, setTab] = useState('gainers');
  const items = tab === 'gainers' ? movers.gainers : movers.losers;

  return (
    <div className={s.movers}>
      <div className={s.movers_tabs}>
        <button
          className={tab === 'gainers' ? s.movers_tabActive : s.movers_tabInactive}
          onClick={() => setTab('gainers')}
        >Gainers</button>
        <button
          className={tab === 'losers' ? s.movers_tabActive : s.movers_tabInactive}
          onClick={() => setTab('losers')}
        >Losers</button>
      </div>
      {loading ? (
        <div style={{ padding: 12 }}><SkeletonMetricRow count={3} /></div>
      ) : items.length === 0 ? (
        <div className={s.movers_empty}>
          No {tab} data available. Scanner data populates during market hours.
        </div>
      ) : (
        <div className={s.movers_list}>
          {items.map((m, i) => (
            <div key={`${m.symbol}-${i}`} className={s.movers_row}>
              <span className={s.movers_symbol}>{m.symbol}</span>
              <span className={s.movers_price}>{m.price > 0 ? `$${m.price.toFixed(2)}` : ''}</span>
              <span className={s.movers_change} style={{
                color: m.change >= 0 ? '#22C55E' : '#EF4444',
                background: m.change >= 0 ? 'rgba(34,197,94,0.1)' : 'rgba(239,68,68,0.1)',
              }}>
                {m.change >= 0 ? '+' : ''}{m.change.toFixed(2)}%
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

