// ─── Live Bot Status Panel (dynamic card grid, uses real bot data) ───────────
// Uses bots from useLiveBots prop. Enriches with telemetry + pnl/summary.
// Heartbeat-age coloring: green <5min, amber 5-15min, red >15min.

function heartbeatColor(lastHeartbeat) {
  if (!lastHeartbeat) return '#EF4444';
  const ts = typeof lastHeartbeat === 'number' ? lastHeartbeat * 1000 : new Date(lastHeartbeat).getTime();
  if (!isFinite(ts)) return '#EF4444';
  const ageMin = (Date.now() - ts) / 60000;
  if (ageMin < 5) return '#22C55E';
  if (ageMin < 15) return '#F59E0B';
  return '#EF4444';
}

function heartbeatAge(lastHeartbeat) {
  if (!lastHeartbeat) return null;
  const ts = typeof lastHeartbeat === 'number' ? lastHeartbeat * 1000 : new Date(lastHeartbeat).getTime();
  if (!isFinite(ts)) return null;
  const ageMin = Math.floor((Date.now() - ts) / 60000);
  if (ageMin < 1) return '<1m ago';
  if (ageMin < 60) return `${ageMin}m ago`;
  const h = Math.floor(ageMin / 60);
  return `${h}h ago`;
}

function BotStatusPanel({ liveBots }) {
  const navigate = useNavigate();
  const [botDetails, setBotDetails] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchData = useCallback(async () => {
    try {
      const [pnl, botList] = await Promise.all([
        api('/pnl/summary', { silent: true }).catch(() => null),
        api('/bots', { silent: true }).catch(() => null),
      ]);
      setBotDetails({ pnl, botList });
    } catch {
      // Silently fail
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const id = setInterval(fetchData, 30000);
    return () => clearInterval(id);
  }, [fetchData]);

  const safeBots = Array.isArray(liveBots) ? liveBots : [];
  const pnlBots = botDetails?.pnl?.bots || {};
  const botListArr = botDetails?.botList?.bots || [];

  // Build cards from actual live bots (no hardcoded names)
  const cards = safeBots.map(bot => {
    const displayName = bot.name || 'UNKNOWN';
    const key = (bot.bot_name || displayName).toLowerCase();
    const lastHb = bot.lastHeartbeat || null;
    const mode = (bot.mode || '').toLowerCase();
    const isPaperBot = mode === 'paper';

    // P&L from pnl/summary or from live bot data
    const pnlData = pnlBots[displayName] || pnlBots[key] || {};
    const dayPnl = pnlData.day_pnl ?? bot.dayPnl ?? bot.pnl?.day ?? 0;
    const totalTrades = pnlData.total_trades ?? bot.trades ?? 0;

    // Strategy count from /api/bots data or from live bot strategies array
    const botFromList = botListArr.find(b =>
      (b.bot_name || '').toLowerCase() === key || (b.display_name || '').toLowerCase() === displayName.toLowerCase()
    );
    const strategies = botFromList?.strategies || bot.strategies || [];
    const strategyCount = Array.isArray(strategies) ? strategies.length : 0;

    const dotColor = heartbeatColor(lastHb);
    const ageLabel = heartbeatAge(lastHb);
    const hasData = true; // bot exists in liveBots so it has data

    return { displayName, hasData, lastHb, ageLabel, dotColor, isPaperBot, dayPnl, totalTrades, strategyCount, equity: bot.equity || 0 };
  });

  if (cards.length === 0) {
    return (
      <GlassPanel padding={0} className={s.panelOuter} aria-label="Live Bot Status">
        <div className={s.panelLabel}>Live Bot Status</div>
        <div style={{ padding: '20px 16px', textAlign: 'center', color: '#8B949E', fontFamily: mono, fontSize: 12 }}>
          No bots connected yet. Connect your broker to see live bot status.
        </div>
      </GlassPanel>
    );
  }

  return (
    <GlassPanel padding={0} className={s.panelOuter} aria-label="Live Bot Status">
      <div className={s.panelLabel} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <span>Live Bot Status</span>
        <span style={{ fontFamily: mono, fontSize: 10, color: HEX.textSecondary, letterSpacing: 0.3, fontWeight: 400 }}>
          auto-refresh 30s
        </span>
      </div>
      <div className={s.botStatus_grid} style={{ gridTemplateColumns: `repeat(${Math.min(cards.length, 4)}, 1fr)` }}>
        {cards.map(card => {
          const pnlColor = card.dayPnl >= 0 ? '#22C55E' : '#EF4444';
          return (
            <div
              key={card.displayName}
              className={s.botStatus_card}
              onClick={() => navigate(`/positions?bot=${card.displayName}`)}
              role="button"
              tabIndex={0}
              onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') e.currentTarget.click(); }}
            >
              {/* Status dot + name row */}
              <div className={s.botStatus_header}>
                <span
                  className={s.botStatus_dot}
                  style={{
                    background: card.dotColor,
                    boxShadow: `0 0 6px ${card.dotColor}70`,
                  }}
                />
                <span className={s.botStatus_name}>{card.displayName}</span>
                {card.isPaperBot && (
                  <span className={s.botStatus_paperBadge}>PAPER</span>
                )}
              </div>

              {/* Heartbeat age */}
              <div className={s.botStatus_hb}>
                {card.ageLabel ? (
                  <span style={{ color: card.dotColor }}>{card.ageLabel}</span>
                ) : (
                  <span style={{ color: '#90A3AF' }}>No heartbeat</span>
                )}
              </div>

              {/* Equity */}
              <div style={{ fontFamily: mono, fontSize: 15, fontWeight: 700, color: '#E5E7DB', marginBottom: 2 }}>
                {fmt$(card.equity)}
              </div>

              {/* Metrics */}
              <div className={s.botStatus_metrics}>
                <div className={s.botStatus_metric}>
                  <span className={s.botStatus_metricLabel}>Day P&amp;L</span>
                  <span className={s.botStatus_metricValue} style={{ color: pnlColor }}>
                    {(card.dayPnl >= 0 ? '+' : '') + fmt$(card.dayPnl)}
                  </span>
                </div>
                <div className={s.botStatus_metric}>
                  <span className={s.botStatus_metricLabel}>Strategies</span>
                  <span className={s.botStatus_metricValue} style={{ color: card.strategyCount > 0 ? '#60A5FA' : '#90A3AF' }}>
                    {card.strategyCount}
                  </span>
                </div>
                <div className={s.botStatus_metric}>
                  <span className={s.botStatus_metricLabel}>Trades</span>
                  <span className={s.botStatus_metricValue} style={{ color: '#E5E7DB' }}>
                    {card.totalTrades}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </GlassPanel>
  );
}

