// ─── Portfolio Snapshot Widget ───────────────────────────────────────────────

function PortfolioSnapshotWidget() {
  const [snapshot, setSnapshot] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const fetchSnapshot = async () => {
      try {
        const [exposureRes, telemetryRes] = await Promise.allSettled([
          api('/risk/exposure', { silent: true }),
          api('/telemetry/latest', { silent: true }),
        ]);
        if (cancelled) return;

        const exposure = exposureRes.status === 'fulfilled' && exposureRes.value && !exposureRes.value.error ? exposureRes.value : null;
        const telemetry = telemetryRes.status === 'fulfilled' && telemetryRes.value && !telemetryRes.value.error ? telemetryRes.value : null;

        if (!exposure && !telemetry) return;

        const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
        const bots = (exposure?.exposure || []).filter(b => !PAPER_BOTS.has((b.bot_name || '').toLowerCase()));
        const totalEquity = bots.reduce((s, b) => s + Number(b.equity || 0), 0);
        const positionsValue = bots.reduce((s, b) => s + Number(b.positions_value || 0), 0);
        const positionsCount = bots.reduce((s, b) => s + Number(b.positions_count || 0), 0);
        const buyingPower = bots.reduce((s, b) => s + Number(b.buying_power || 0), 0);
        const cashAmount = totalEquity > 0 ? totalEquity - positionsValue : 0;

        // Sum day_pnl across all gateway accounts from telemetry
        let dayPnl = 0;
        if (telemetry) {
          const entries = Array.isArray(telemetry) ? telemetry : (telemetry.gateways || telemetry.accounts || [telemetry]);
          for (const entry of entries) {
            dayPnl += Number(entry.day_pnl ?? entry.daily_pnl ?? 0);
          }
        }

        setSnapshot({
          totalValue: totalEquity,
          dayChange: dayPnl,
          totalExposure: positionsValue,
          positionCount: positionsCount,
          cash: cashAmount,
          buyingPower,
        });
      } catch {
        // silently fail
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    fetchSnapshot();
    const iv = setInterval(fetchSnapshot, 60000);
    return () => { cancelled = true; clearInterval(iv); };
  }, []);

  if (loading) return <div style={{ padding: 12 }}><SkeletonMetricRow count={3} /></div>;
  if (!snapshot) return null;

  const totalValue = Number(snapshot.totalValue || 0);
  const dayChange = Number(snapshot.dayChange || 0);
  const totalExposure = Number(snapshot.totalExposure || 0);
  const positionCount = Number(snapshot.positionCount || 0);
  const cash = Number(snapshot.cash || 0);
  const cashPct = totalValue > 0 ? (cash / totalValue * 100) : 0;
  const dayChangePct = totalValue > 0 ? (dayChange / (totalValue - dayChange) * 100) : 0;
  const pnlColor = dayChange >= 0 ? '#22C55E' : '#EF4444';

  const items = [
    { label: 'Portfolio Value', value: fmt$(totalValue), color: '#E5E7DB' },
    { label: 'Day Change', value: `${dayChange >= 0 ? '+' : ''}${fmt$(dayChange)}`, sub: `${dayChangePct >= 0 ? '+' : ''}${dayChangePct.toFixed(2)}%`, color: pnlColor },
    { label: 'Exposure', value: fmt$(totalExposure), color: '#60A5FA' },
    { label: 'Positions', value: String(positionCount), color: '#E5E7DB' },
    { label: 'Cash', value: cashPct > 0 ? `${cashPct.toFixed(1)}%` : '--', color: '#A78BFA' },
  ];

  return (
    <div style={{
      display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 12,
      padding: '12px 16px',
    }}>
      {items.map(item => (
        <div key={item.label} style={{ textAlign: 'center' }}>
          <div style={{ fontFamily: body, fontSize: 10, color: '#90A3AF', textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 4 }}>
            {item.label}
          </div>
          <div style={{ fontFamily: mono, fontSize: 14, fontWeight: 700, color: item.color, fontVariantNumeric: 'tabular-nums' }}>
            {item.value}
          </div>
          {item.sub && (
            <div style={{ fontFamily: mono, fontSize: 10, color: item.color, marginTop: 2 }}>
              {item.sub}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

