import { motion, AnimatePresence } from 'framer-motion';
import useTransfers from '../hooks/useTransfers';

const fmt$ = (n) => {
  const abs = Math.abs(n);
  return abs >= 1000 ? `$${(abs / 1000).toFixed(1)}k` : `$${abs.toFixed(2)}`;
};

export default function TransferConfirmBanner() {
  const { pending, confirmTransfer, rejectTransfer } = useTransfers();

  if (!pending.length) return null;

  return (
    <AnimatePresence>
      {pending.map((t) => (
        <motion.div
          key={t.id}
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          exit={{ opacity: 0, height: 0 }}
          style={{
            background: 'rgba(210, 153, 34, 0.12)',
            border: '1px solid rgba(210, 153, 34, 0.3)',
            borderRadius: 10,
            padding: '10px 16px',
            marginBottom: 8,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            gap: 12,
            fontSize: 13,
          }}
        >
          <span style={{ color: '#F59E0B' }}>
            Detected {t.transfer_type} of <strong>{fmt$(t.amount)}</strong> to{' '}
            <strong>{(t.bot_name || '').toUpperCase()}</strong>
            {t.equity_before != null && t.equity_after != null && (
              <span style={{ color: '#8B949E', marginLeft: 8 }}>
                ({fmt$(t.equity_before)} &rarr; {fmt$(t.equity_after)})
              </span>
            )}
          </span>
          <div style={{ display: 'flex', gap: 8, flexShrink: 0 }}>
            <button
              onClick={() => confirmTransfer(t.id)}
              style={{
                background: '#22C55E', color: '#0D1117', border: 'none',
                borderRadius: 6, padding: '4px 12px', cursor: 'pointer',
                fontWeight: 600, fontSize: 13,
              }}
            >
              Confirm
            </button>
            <button
              onClick={() => rejectTransfer(t.id)}
              style={{
                background: 'transparent', color: '#8B949E',
                border: '1px solid #30363D', borderRadius: 6,
                padding: '4px 12px', cursor: 'pointer', fontSize: 13,
              }}
            >
              Not a deposit
            </button>
          </div>
        </motion.div>
      ))}
    </AnimatePresence>
  );
}
