import { useState, useEffect, useRef, useCallback } from 'react';
import { api } from '../utils/api';

const mono = "'JetBrains Mono', 'SF Mono', monospace";
const body = "'Plus Jakarta Sans', -apple-system, sans-serif";

const STATIC_MESSAGES = [
  'Signal engine scanning 600 symbols...',
  '83 strategies evaluating market conditions...',
  'Risk engine monitoring exposure...',
  'Allocation engine distributing capital...',
  'Cross-bot correlation analysis running...',
  'Scanning for breakout setups...',
];

export default function SystemActivityPulse() {
  const [dismissed, setDismissed] = useState(() => sessionStorage.getItem('aura_pulse_dismissed') === 'true');
  const [messageIdx, setMessageIdx] = useState(0);
  const [messages, setMessages] = useState(STATIC_MESSAGES);
  const [countdown, setCountdown] = useState(60);
  const [fade, setFade] = useState(true);
  const countdownRef = useRef(60);
  const intervalRef = useRef(null);

  // Check if user is within first 7 days
  const isNewUser = useCallback(() => {
    const onboarded = localStorage.getItem('aura_onboarding_completed');
    if (!onboarded) return true;
    const daysSince = (Date.now() - new Date(onboarded).getTime()) / (1000 * 60 * 60 * 24);
    return daysSince <= 7;
  }, []);

  // Fetch real signal data and engine status
  const fetchStatus = useCallback(async () => {
    try {
      const [statusRes, signalsRes] = await Promise.allSettled([
        api('/realtime/status', { silent: true }),
        api('/realtime/signals', { silent: true }),
      ]);

      const newMessages = [...STATIC_MESSAGES];

      // Inject real signal names if available
      const signals = signalsRes.status === 'fulfilled'
        ? (Array.isArray(signalsRes.value) ? signalsRes.value : signalsRes.value?.signals || [])
        : [];
      if (signals.length > 0) {
        const recent = signals.slice(0, 3);
        recent.forEach((sig) => {
          const sym = sig.symbol || sig.ticker || '';
          const dir = (sig.direction || sig.side || 'BUY').toUpperCase();
          const conf = Number(sig.confidence ?? sig.score ?? 0);
          const confDisplay = conf > 1 ? conf.toFixed(0) : (conf * 100).toFixed(0);
          const strategy = sig.strategy || sig.strategy_name || 'breakout';
          if (sym) {
            newMessages.push(`New signal: ${dir} ${sym} \u2014 ${strategy} (${confDisplay}% confidence)`);
          }
        });
      }

      // Inject engine status if available
      const status = statusRes.status === 'fulfilled' ? statusRes.value : null;
      if (status) {
        const signalCount = status.signal_count ?? status.signalCount ?? signals.length;
        if (signalCount > 0) {
          newMessages.push(`${signalCount} active signals detected this session`);
        }
        if (status.next_scan || status.nextScan) {
          const nextScan = new Date(status.next_scan || status.nextScan);
          const secsUntil = Math.max(0, Math.round((nextScan.getTime() - Date.now()) / 1000));
          if (secsUntil > 0 && secsUntil < 300) {
            countdownRef.current = secsUntil;
            setCountdown(secsUntil);
          }
        }
      }

      setMessages(newMessages);
    } catch {
      // Keep static messages on failure
    }
  }, []);

  // Fetch status every 30s
  useEffect(() => {
    fetchStatus();
    const iv = setInterval(fetchStatus, 30000);
    return () => clearInterval(iv);
  }, [fetchStatus]);

  // Countdown timer (60s cycle)
  useEffect(() => {
    const iv = setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) {
          countdownRef.current = 60;
          return 60;
        }
        countdownRef.current = prev - 1;
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(iv);
  }, []);

  // Rotate messages every 5s with fade transition
  useEffect(() => {
    intervalRef.current = setInterval(() => {
      setFade(false);
      setTimeout(() => {
        setMessageIdx((prev) => (prev + 1) % messages.length);
        setFade(true);
      }, 300);
    }, 5000);
    return () => clearInterval(intervalRef.current);
  }, [messages.length]);

  // Don't show if dismissed this session, or if user is past 7 days
  if (dismissed) return null;
  if (!isNewUser()) return null;

  const handleDismiss = () => {
    sessionStorage.setItem('aura_pulse_dismissed', 'true');
    setDismissed(true);
  };

  const fmtCountdown = `${Math.floor(countdown / 60)}:${String(countdown % 60).padStart(2, '0')}`;

  return (
    <>
      <style>{`
        @keyframes sap-pulse {
          0%, 100% { opacity: 1; box-shadow: 0 0 4px #22C55E; }
          50% { opacity: 0.4; box-shadow: 0 0 8px #22C55E80; }
        }
        @keyframes sap-slideIn {
          from { opacity: 0; transform: translateY(-8px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
      <div
        style={{
          height: 40,
          background: 'linear-gradient(90deg, #0B0F14 0%, #0F1620 100%)',
          borderLeft: '3px solid #22C55E',
          borderRadius: 6,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '0 16px',
          marginBottom: 12,
          animation: 'sap-slideIn 0.4s ease',
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        {/* Subtle scan line effect */}
        <div style={{
          position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,
          background: 'linear-gradient(90deg, transparent 0%, rgba(34,197,94,0.03) 50%, transparent 100%)',
          pointerEvents: 'none',
        }} />

        {/* Left: pulsing dot + SYSTEM ACTIVE */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}>
          <div style={{
            width: 7, height: 7, borderRadius: '50%',
            background: '#22C55E',
            animation: 'sap-pulse 1.5s ease-in-out infinite',
          }} />
          <span style={{
            fontFamily: mono, fontSize: 10, fontWeight: 700,
            color: '#22C55E', letterSpacing: '0.08em',
          }}>
            SYSTEM ACTIVE
          </span>
        </div>

        {/* Center: rotating message */}
        <div style={{
          flex: 1, textAlign: 'center', overflow: 'hidden',
          margin: '0 16px',
        }}>
          <span style={{
            fontFamily: body, fontSize: 12, color: '#90A3AF',
            opacity: fade ? 1 : 0,
            transition: 'opacity 0.3s ease',
            whiteSpace: 'nowrap',
          }}>
            {messages[messageIdx % messages.length]}
            {' '}
            <span style={{ fontFamily: mono, fontSize: 10, color: '#4B5563' }}>
              Next scan {fmtCountdown}
            </span>
          </span>
        </div>

        {/* Right: auto-update label + dismiss */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, flexShrink: 0 }}>
          <span style={{
            fontFamily: body, fontSize: 10, color: '#4B5563',
            whiteSpace: 'nowrap',
          }}>
            Signals update automatically
          </span>
          <button
            onClick={handleDismiss}
            style={{
              background: 'none', border: 'none', cursor: 'pointer',
              color: '#4B5563', padding: 2, lineHeight: 1,
              display: 'flex', alignItems: 'center',
            }}
            aria-label="Dismiss system activity bar"
          >
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="18" y1="6" x2="6" y2="18" />
              <line x1="6" y1="6" x2="18" y2="18" />
            </svg>
          </button>
        </div>
      </div>
    </>
  );
}
