import { useState, useEffect, useRef } from "react";
import { getApiBase } from '../utils/platform';

/**
 * Hook: Real-time bot status streaming via WebSocket.
 * Connects to /api/ws/bots and pushes updates every 5 seconds.
 * Falls back to HTTP polling if WebSocket unavailable.
 */
export default function useBotStream(pollMs = 6000) {
  const [botStatus, setBotStatus] = useState(null);
  const wsRef = useRef(null);
  const retryRef = useRef(0);

  useEffect(() => {
    let active = true;
    let fallbackInterval = null;

    const connectWs = () => {
      const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
      const url = `${protocol}//${window.location.host}/api/ws/bots`;

      try {
        const ws = new WebSocket(url);
        wsRef.current = ws;

        ws.onopen = () => {
          retryRef.current = 0;
          if (fallbackInterval) {
            clearInterval(fallbackInterval);
            fallbackInterval = null;
          }
        };

        ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            if (active) setBotStatus(data);
          } catch (e) {
            console.warn("[Bot WS] Parse error:", e);
          }
        };

        ws.onclose = () => {
          if (!active) return;
          const delay = Math.min(1000 * Math.pow(2, retryRef.current), 30000);
          retryRef.current++;
          setTimeout(connectWs, delay);
          if (!fallbackInterval) {
            fallbackInterval = setInterval(fetchHttp, pollMs);
          }
        };

        ws.onerror = () => {
          ws.close();
        };
      } catch {
        if (!fallbackInterval) {
          fallbackInterval = setInterval(fetchHttp, pollMs);
        }
      }
    };

    const fetchHttp = async () => {
      try {
        const r = await fetch(`${getApiBase()}/telemetry/latest`);
        if (r.ok) {
          const data = await r.json();
          if (active) setBotStatus({ timestamp: Date.now() / 1000, bots: data.bots || {} });
        }
      } catch {
        // Ignore polling errors
      }
    };

    connectWs();

    return () => {
      active = false;
      if (wsRef.current) wsRef.current.close();
      if (fallbackInterval) clearInterval(fallbackInterval);
    };
  }, [pollMs]);

  return botStatus;
}
