import { useState, useEffect, useRef, useCallback } from "react";
import { getApiBase } from '../utils/platform';

/**
 * Hook: Real-time kill switch + targets streaming via WebSocket.
 * Connects to /api/ws and pushes updates every second.
 * Returns { enabled, kill, pause, targets, ts }.
 * Falls back to HTTP polling if WebSocket unavailable.
 */
export default function useKillSwitchStream(pollMs = 3000) {
  const [state, setState] = useState(null);
  const wsRef = useRef(null);
  const retryRef = useRef(0);
  const cbRef = useRef(null);

  // Allow consumers to register a callback for state changes
  const onStateChange = useCallback((cb) => {
    cbRef.current = cb;
  }, []);

  useEffect(() => {
    let active = true;
    let fallbackInterval = null;

    const update = (data) => {
      if (!active) return;
      setState(data);
      if (cbRef.current) cbRef.current(data);
    };

    const connectWs = () => {
      const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
      const url = `${protocol}//${window.location.host}/api/ws`;

      try {
        const ws = new WebSocket(url);
        wsRef.current = ws;

        ws.onopen = () => {
          retryRef.current = 0;
          if (fallbackInterval) {
            clearInterval(fallbackInterval);
            fallbackInterval = null;
          }
        };

        ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            update(data);
          } catch (e) {
            console.warn("[KillSwitch WS] Parse error:", e);
          }
        };

        ws.onclose = () => {
          if (!active) return;
          const delay = Math.min(1000 * Math.pow(2, retryRef.current), 30000);
          retryRef.current++;
          setTimeout(connectWs, delay);
          if (!fallbackInterval) {
            fallbackInterval = setInterval(fetchHttp, pollMs);
          }
        };

        ws.onerror = () => {
          ws.close();
        };
      } catch {
        if (!fallbackInterval) {
          fallbackInterval = setInterval(fetchHttp, pollMs);
        }
      }
    };

    const fetchHttp = async () => {
      try {
        const r = await fetch(`${getApiBase()}/control/health`);
        if (r.ok) {
          const data = await r.json();
          update({
            ts: Date.now() / 1000,
            enabled: !data.kill_switch_active,
            kill: { enabled: data.kill_switch_active || false },
            pause: { enabled: false },
          });
        }
      } catch {
        // Ignore polling errors
      }
    };

    connectWs();

    return () => {
      active = false;
      if (wsRef.current) wsRef.current.close();
      if (fallbackInterval) clearInterval(fallbackInterval);
    };
  }, [pollMs]);

  return { state, onStateChange };
}
