/* ═══════════════════════════════════════════════════════════════════════════
   WHILE YOU WERE AWAY CARD
   Shows a summary of activity when the user returns after 4+ hours.
   Creates urgency: "things happen when I'm not watching."
   Fetches from /api/telemetry/latest + /api/positions + /api/scanners/signals/live
   Dismisses with "Got it" — won't show again until next 4hr+ absence.
   ═══════════════════════════════════════════════════════════════════════════ */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { api } from '../utils/api';

const mono = "'JetBrains Mono', 'SF Mono', monospace";
const body = "'Plus Jakarta Sans', -apple-system, sans-serif";

const LAST_SEEN_KEY = 'aura_last_seen';
const DISMISSED_KEY = 'aura_away_dismissed';
const MIN_AWAY_MS = 4 * 60 * 60 * 1000; // 4 hours

function fmt$(v) {
  const n = Number(v);
  if (v == null || !isFinite(n)) return '$0.00';
  return new Intl.NumberFormat('en-US', {
    style: 'currency', currency: 'USD', minimumFractionDigits: 2,
  }).format(Math.abs(n));
}

function fmtDuration(ms) {
  const hours = Math.floor(ms / (1000 * 60 * 60));
  if (hours < 1) return 'less than an hour';
  if (hours === 1) return '1 hour';
  if (hours < 24) return `${hours} hours`;
  const days = Math.floor(hours / 24);
  if (days === 1) return '1 day';
  return `${days} days`;
}

export default function WhileYouWereAway() {
  const [visible, setVisible] = useState(false);
  const [summary, setSummary] = useState(null);
  const [awayDuration, setAwayDuration] = useState(0);
  const checkedRef = useRef(false);

  useEffect(() => {
    // Only check once per mount
    if (checkedRef.current) return;
    checkedRef.current = true;

    const now = Date.now();
    const lastSeen = Number(localStorage.getItem(LAST_SEEN_KEY) || 0);
    const dismissedAt = Number(localStorage.getItem(DISMISSED_KEY) || 0);

    // Update last seen immediately
    localStorage.setItem(LAST_SEEN_KEY, String(now));

    // If never visited before, or away less than 4h, skip
    if (!lastSeen || (now - lastSeen) < MIN_AWAY_MS) return;

    // If already dismissed for this session (within last 30 min), skip
    if (dismissedAt && (now - dismissedAt) < 30 * 60 * 1000) return;

    const duration = now - lastSeen;
    setAwayDuration(duration);

    // Fetch summary data
    fetchSummary().then(data => {
      if (data && hasAnythingToShow(data)) {
        setSummary(data);
        setVisible(true);
      }
    });
  }, []);

  // Keep updating last_seen while the page is active
  useEffect(() => {
    const iv = setInterval(() => {
      localStorage.setItem(LAST_SEEN_KEY, String(Date.now()));
    }, 60_000); // Update every minute
    return () => clearInterval(iv);
  }, []);

  const fetchSummary = useCallback(async () => {
    try {
      const [telemetry, ordersData, signalsData] = await Promise.all([
        api('/telemetry/latest', { silent: true }),
        api('/orders/blotter', { silent: true }),
        api('/scanners/signals/live', { silent: true }),
      ]);

      // Count recent trades from blotter (orders filled since last seen)
      const orders = Array.isArray(ordersData) ? ordersData : (ordersData?.orders || []);
      const recentTrades = orders.filter(o =>
        o.status === 'Filled' || o.status === 'filled'
      ).length;

      // Calculate total P&L from bot telemetry — exclude paper/marketing bots
      const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
      const META_KEYS = new Set(['gateway_connected', 'accounts', 'equity', 'position_count', 'trade_count']);
      let totalPnl = 0;
      const allBots = telemetry?.bots || {};
      const botEntries = Object.entries(allBots).filter(
        ([name, v]) => !META_KEYS.has(name) && !PAPER_BOTS.has(name.toLowerCase()) && v && typeof v === 'object'
      );
      botEntries.forEach(([, bot]) => {
        totalPnl += Number(bot?.pnl?.day ?? bot?.dayPnl ?? 0);
      });

      // Count active signals
      const signals = Array.isArray(signalsData) ? signalsData : (signalsData?.signals || []);
      const activeSignals = signals.length;

      // Count active bots
      const activeBots = botEntries.filter(([, b]) =>
        b?.status === 'OK' || b?.status === 'LIVE'
      ).length;
      const totalBots = botEntries.length;

      return {
        recentTrades,
        totalPnl,
        activeSignals,
        activeBots,
        totalBots,
      };
    } catch {
      return null;
    }
  }, []);

  function hasAnythingToShow(data) {
    if (!data) return false;
    return data.recentTrades > 0 || data.totalPnl !== 0 || data.activeSignals > 0;
  }

  const handleDismiss = () => {
    setVisible(false);
    localStorage.setItem(DISMISSED_KEY, String(Date.now()));
  };

  if (!visible || !summary) return null;

  const isPositive = summary.totalPnl >= 0;
  const pnlColor = isPositive ? 'var(--color-green, #22C55E)' : 'var(--color-red, #EF4444)';

  // Build summary lines
  const lines = [];
  if (summary.recentTrades > 0) {
    lines.push({
      icon: (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--color-blue, #60A5FA)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
        </svg>
      ),
      text: `${summary.recentTrades} trade${summary.recentTrades !== 1 ? 's' : ''} executed`,
      color: 'var(--color-textPrimary, #E5E7DB)',
    });
  }
  if (summary.totalPnl !== 0) {
    lines.push({
      icon: (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={pnlColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <line x1="12" y1="1" x2="12" y2="23" />
          <path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6" />
        </svg>
      ),
      text: `${isPositive ? '+' : '-'}${fmt$(summary.totalPnl)} P&L today`,
      color: pnlColor,
    });
  }
  if (summary.activeSignals > 0) {
    lines.push({
      icon: (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--color-amber, #F59E0B)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" />
        </svg>
      ),
      text: `${summary.activeSignals} signal${summary.activeSignals !== 1 ? 's' : ''} currently firing`,
      color: 'var(--color-amber, #F59E0B)',
    });
  }

  if (lines.length === 0) return null;

  return (
    <AnimatePresence>
      {visible && (
        <motion.div
          initial={{ opacity: 0, y: -12, height: 0 }}
          animate={{ opacity: 1, y: 0, height: 'auto' }}
          exit={{ opacity: 0, y: -12, height: 0 }}
          transition={{ duration: 0.3, ease: [0.4, 0, 0.2, 1] }}
          style={{ marginBottom: 16, overflow: 'hidden' }}
        >
          <div style={{
            background: 'var(--color-surface, #0F1620)',
            border: '1px solid var(--color-border, #1F2A37)',
            borderRadius: 10,
            padding: '16px 18px',
            position: 'relative',
            overflow: 'hidden',
          }}>
            {/* Subtle accent line at top */}
            <div style={{
              position: 'absolute',
              top: 0, left: 0, right: 0,
              height: 2,
              background: 'linear-gradient(90deg, var(--color-blue, #60A5FA), var(--color-purple, #A78BFA), var(--color-blue, #60A5FA))',
              opacity: 0.5,
            }} />

            {/* Header */}
            <div style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'flex-start',
              marginBottom: 12,
            }}>
              <div>
                <div style={{
                  fontFamily: body,
                  fontSize: 13,
                  fontWeight: 700,
                  color: 'var(--color-textPrimary, #E5E7DB)',
                }}>
                  While you were away
                </div>
                <div style={{
                  fontFamily: mono,
                  fontSize: 10,
                  color: 'var(--color-textSecondary, #90A3AF)',
                  marginTop: 2,
                }}>
                  Gone for {fmtDuration(awayDuration)}
                </div>
              </div>

              {/* Bot status pill */}
              {summary.totalBots > 0 && (
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 4,
                  padding: '3px 8px',
                  borderRadius: 4,
                  background: summary.activeBots === summary.totalBots
                    ? 'rgba(34,197,94,0.1)'
                    : 'rgba(245,158,11,0.1)',
                  border: `1px solid ${
                    summary.activeBots === summary.totalBots
                      ? 'rgba(34,197,94,0.2)'
                      : 'rgba(245,158,11,0.2)'
                  }`,
                }}>
                  <span style={{
                    width: 5, height: 5, borderRadius: '50%',
                    background: summary.activeBots === summary.totalBots
                      ? 'var(--color-green, #22C55E)'
                      : 'var(--color-amber, #F59E0B)',
                  }} />
                  <span style={{
                    fontFamily: mono, fontSize: 10, fontWeight: 600,
                    color: summary.activeBots === summary.totalBots
                      ? 'var(--color-green, #22C55E)'
                      : 'var(--color-amber, #F59E0B)',
                  }}>
                    {summary.activeBots}/{summary.totalBots} bots active
                  </span>
                </div>
              )}
            </div>

            {/* Summary lines */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {lines.map((line, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, x: -8 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.1 + i * 0.08, duration: 0.2 }}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                  }}
                >
                  <div style={{
                    width: 24, height: 24,
                    borderRadius: 6,
                    background: 'rgba(255,255,255,0.04)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    flexShrink: 0,
                  }}>
                    {line.icon}
                  </div>
                  <span style={{
                    fontFamily: body,
                    fontSize: 12,
                    fontWeight: 600,
                    color: line.color,
                  }}>
                    {line.text}
                  </span>
                </motion.div>
              ))}
            </div>

            {/* Dismiss button */}
            <div style={{ marginTop: 14, display: 'flex', justifyContent: 'flex-end' }}>
              <button
                onClick={handleDismiss}
                style={{
                  fontFamily: body,
                  fontSize: 11,
                  fontWeight: 600,
                  color: 'var(--color-textSecondary, #90A3AF)',
                  background: 'rgba(255,255,255,0.04)',
                  border: '1px solid var(--color-border, #1F2A37)',
                  borderRadius: 6,
                  padding: '6px 14px',
                  cursor: 'pointer',
                  transition: 'all 0.15s ease',
                }}
                onMouseEnter={(e) => {
                  e.target.style.background = 'rgba(255,255,255,0.08)';
                  e.target.style.color = 'var(--color-textPrimary, #E5E7DB)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.background = 'rgba(255,255,255,0.04)';
                  e.target.style.color = 'var(--color-textSecondary, #90A3AF)';
                }}
              >
                Got it
              </button>
            </div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
