import { useState } from 'react';
import * as Popover from '@radix-ui/react-popover';
import { apiPost } from '../utils/api';

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

function statusColor(status) {
  if (!status) return C.textSecondary;
  const s = String(status).toLowerCase();
  if (['active', 'online', 'running', 'ok', 'live'].includes(s)) return C.green;
  if (['degraded', 'stale', 'warning', 'reconnecting'].includes(s)) return C.amber;
  if (['stopped', 'offline', 'error', 'disconnected', 'killed'].includes(s)) return C.red;
  return C.textSecondary;
}

/**
 * BotControlPopover — shows on bot card click.
 * Props: bot (object with name, status, equity, positions, riskBudget, mode), onAction(action)
 */
export default function BotControlPopover({ children, bot, onAction }) {
  const [open, setOpen] = useState(false);
  const [actionLoading, setActionLoading] = useState(false);

  if (!bot) return children;

  const bStatus = bot.status || bot.state || 'unknown';
  const bColor = statusColor(bStatus);
  const isActive = ['active', 'online', 'running', 'ok', 'live'].includes(String(bStatus).toLowerCase());

  const handleAction = async (action) => {
    setActionLoading(true);
    try {
      if (action === 'kill') {
        await apiPost('/bots/mode', { bot: bot.name?.toLowerCase(), mode: 'stopped' });
      } else if (action === 'start') {
        await apiPost('/bots/mode', { bot: bot.name?.toLowerCase(), mode: 'live' });
      }
      onAction?.(action, bot.name);
    } catch (e) {
      console.error('Bot action failed:', e);
    } finally {
      setActionLoading(false);
    }
  };

  const formatCurrency = (v) => {
    if (v == null || isNaN(v)) return '--';
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0 }).format(v);
  };

  return (
    <Popover.Root open={open} onOpenChange={setOpen}>
      <Popover.Trigger asChild>
        {children}
      </Popover.Trigger>
      <Popover.Portal>
        <Popover.Content
          sideOffset={8}
          style={{
            width: 300, background: C.surface, border: `1px solid ${C.border}`,
            borderRadius: 14, boxShadow: '0 12px 40px rgba(0,0,0,0.5)',
            zIndex: 1000, overflow: 'hidden',
          }}
        >
          {/* Header */}
          <div style={{
            padding: '14px 16px', borderBottom: `1px solid ${C.border}`,
            display: 'flex', alignItems: 'center', gap: 12,
          }}>
            <span style={{
              width: 10, height: 10, borderRadius: '50%', background: bColor,
              boxShadow: `0 0 8px ${bColor}`,
            }} />
            <span style={{ fontFamily: mono, fontSize: 16, fontWeight: 700, color: bot.accent || C.textPrimary }}>
              {String(bot.name || '--')}
            </span>
            <span style={{
              marginLeft: 'auto', fontFamily: mono, fontSize: 10, fontWeight: 600,
              color: bColor, textTransform: 'uppercase', background: `${bColor}15`,
              padding: '2px 8px', borderRadius: 6,
            }}>
              {String(bStatus)}
            </span>
          </div>

          {/* Stats grid */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 0 }}>
            {[
              { label: 'Equity', value: formatCurrency(typeof bot.equity === 'object' ? bot.equity?.current : bot.equity) },
              { label: 'Positions', value: String(bot.positions ?? '--'), color: C.blue },
              { label: 'Mode', value: String(bot.mode || '--') },
              { label: 'Risk Budget', value: bot.riskBudget != null ? `${bot.riskBudget}%` : '--', color: C.amber },
            ].map(s => (
              <div key={s.label} style={{ padding: '10px 16px', borderBottom: `1px solid ${C.border}` }}>
                <div style={{ fontSize: 10, color: C.textSecondary, textTransform: 'uppercase', marginBottom: 4, fontFamily: body }}>{s.label}</div>
                <div style={{ fontFamily: mono, fontSize: 13, fontWeight: 600, color: s.color || C.textPrimary }}>{String(s.value ?? '--')}</div>
              </div>
            ))}
          </div>

          {/* Actions */}
          <div style={{ padding: '12px 16px', display: 'flex', gap: 8 }}>
            {isActive ? (
              <button
                onClick={() => handleAction('kill')}
                disabled={actionLoading}
                style={{
                  flex: 1, padding: '8px 0', borderRadius: 6,
                  border: `1px solid ${C.red}40`, background: `${C.red}15`,
                  color: C.red, fontFamily: mono, fontSize: 13, fontWeight: 600,
                  cursor: actionLoading ? 'not-allowed' : 'pointer',
                }}
              >
                {actionLoading ? '...' : 'Stop Bot'}
              </button>
            ) : (
              <button
                onClick={() => handleAction('start')}
                disabled={actionLoading}
                style={{
                  flex: 1, padding: '8px 0', borderRadius: 6,
                  border: `1px solid ${C.green}40`, background: `${C.green}15`,
                  color: C.green, fontFamily: mono, fontSize: 13, fontWeight: 600,
                  cursor: actionLoading ? 'not-allowed' : 'pointer',
                }}
              >
                {actionLoading ? '...' : 'Start Bot'}
              </button>
            )}
          </div>

          <Popover.Arrow style={{ fill: C.surface }} />
        </Popover.Content>
      </Popover.Portal>
    </Popover.Root>
  );
}
