import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';

export default function useTransfers() {
  const [pending, setPending] = useState([]);

  const fetchPending = useCallback(async () => {
    try {
      const data = await api('/transfers/pending', { silent: true });
      if (data?.transfers) setPending(data.transfers);
    } catch { /* ignore */ }
  }, []);

  const confirmTransfer = useCallback(async (id) => {
    try {
      await api(`/transfers/${id}/confirm`, { method: 'PUT' });
      setPending(prev => prev.filter(t => t.id !== id));
    } catch { /* ignore */ }
  }, []);

  const rejectTransfer = useCallback(async (id) => {
    try {
      await api(`/transfers/${id}/reject`, { method: 'PUT' });
      setPending(prev => prev.filter(t => t.id !== id));
    } catch { /* ignore */ }
  }, []);

  useEffect(() => {
    fetchPending();
    const interval = setInterval(fetchPending, 30000);
    return () => clearInterval(interval);
  }, [fetchPending]);

  return { pending, confirmTransfer, rejectTransfer, refresh: fetchPending };
}
